import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const verifyFace = async (base64Image: string): Promise<{ isVerified: boolean; confidence: number; message: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
          { text: "Analisis gambar ini. Apakah ini adalah wajah manusia yang jelas untuk tujuan verifikasi absensi? Jawab dalam format JSON: { 'isFace': boolean, 'confidence': number, 'message': string }. Pastikan 'isFace' true jika wajah terlihat jelas, 'confidence' antara 0-1, dan 'message' berisi deskripsi singkat." }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });

    const result = JSON.parse(response.text || '{}');
    return {
      isVerified: result.isFace || false,
      confidence: result.confidence || 0,
      message: result.message || "Gagal melakukan verifikasi."
    };
  } catch (error) {
    console.error("Face verification error:", error);
    return { isVerified: false, confidence: 0, message: "Terjadi kesalahan sistem saat verifikasi wajah." };
  }
};

