import { User, AttendanceRecord, LeaveRequest, Announcement } from '../types';

class GasService {
  private users: User[] = [
    { id: '1', name: 'Admin Presensi', email: 'admin@company.com', role: 'admin', department: 'HR' },
    { id: '2', name: 'Budi Santoso', email: 'budi@company.com', role: 'employee', department: 'IT' }
  ];

  private attendance: AttendanceRecord[] = [];
  private leaves: LeaveRequest[] = [];
  private announcements: Announcement[] = [
    { id: '1', title: 'Libur Nasional', content: 'Hari Senin besok kantor libur dalam rangka Hari Raya.', date: '2024-03-20', author: 'HR Department' }
  ];

  async login(email: string): Promise<User | null> {
    const user = this.users.find(u => u.email === email);
    return user || null;
  }

  async register(userData: Partial<User>): Promise<User> {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'User',
      email: userData.email || '',
      role: 'employee',
      department: userData.department || 'General',
      profileImage: userData.profileImage
    };
    this.users.push(newUser);
    return newUser;
  }

  async submitAttendance(record: Partial<AttendanceRecord>): Promise<AttendanceRecord> {
    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: record.userId || '',
      userName: record.userName || '',
      date: new Date().toLocaleDateString('id-ID'),
      clockIn: record.clockIn || new Date().toLocaleTimeString('id-ID'),
      latIn: record.latIn || 0,
      lngIn: record.lngIn || 0,
      status: record.status || 'hadir',
      wifiVerified: record.wifiVerified || false,
      selfieIn: record.selfieIn
    };
    this.attendance.push(newRecord);
    return newRecord;
  }

  async updateAttendance(id: string, update: Partial<AttendanceRecord>): Promise<void> {
    const index = this.attendance.findIndex(a => a.id === id);
    if (index !== -1) {
      this.attendance[index] = { ...this.attendance[index], ...update };
    }
  }

  async getAttendance(userId?: string): Promise<AttendanceRecord[]> {
    return userId ? this.attendance.filter(a => a.userId === userId) : this.attendance;
  }

  async submitLeave(leave: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const newLeave: LeaveRequest = {
      id: Math.random().toString(36).substr(2, 9),
      userId: leave.userId || '',
      userName: leave.userName || '',
      startDate: leave.startDate || '',
      endDate: leave.endDate || '',
      reason: leave.reason || '',
      status: 'pending',
      type: leave.type || 'cuti'
    };
    this.leaves.push(newLeave);
    return newLeave;
  }

  async getLeaves(userId?: string): Promise<LeaveRequest[]> {
    return userId ? this.leaves.filter(l => l.userId === userId) : this.leaves;
  }

  async getAnnouncements(): Promise<Announcement[]> {
    return this.announcements;
  }
}

