/**
 * GAS (Google Apps Script) Code for PresensiGo
 * 
 * Instructions:
 * 1. Open Google Sheets.
 * 2. Create sheets: "Users", "Attendance", "Leaves", "Announcements".
 * 3. Go to Extensions > Apps Script.
 * 4. Paste this code and click Deploy > New Deployment > Web App.
 * 5. Set "Execute as: Me" and "Who has access: Anyone".
 * 6. Copy the Web App URL and use it in your frontend gasService.ts.
 */

function doGet(e) {
  return handleRequest(e);
}

function doPost(e) {
  return handleRequest(e);
}

function handleRequest(e) {
  const action = e.parameter.action;
  const sheet = SpreadsheetApp.getActiveSpreadsheet();

  try {
    switch (action) {
      case 'login':
        return loginUser(e.parameter.email);
      case 'register':
        return registerUser(JSON.parse(e.postData.contents));
      case 'submitAttendance':
        return saveAttendance(JSON.parse(e.postData.contents));
      case 'getAttendance':
        return getAttendanceData(e.parameter.userId);
      case 'getAnnouncements':
        return getAnnouncements();
      default:
        return createResponse({ error: "Invalid action" });
    }
  } catch (err) {
    return createResponse({ error: err.message });
  }
}

function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

// Implement your CRUD logic here based on your spreadsheet structure
// For brevity, these are templates to get you started:

function loginUser(email) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Users");
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][1] === email) { // assuming email is in column B
      return createResponse({
        id: data[i][0],
        name: data[i][2],
        email: data[i][1],
        role: data[i][3],
        department: data[i][4]
      });
    }
  }
  return createResponse(null);
}

function saveAttendance(data) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Attendance");
  sheet.appendRow([
    new Date(),
    data.userId,
    data.userName,
    data.clockIn,
    data.latIn,
    data.lngIn,
    data.status,
    data.selfieIn
  ]);
  return createResponse({ success: true });
}

