        return getDataByUserId("Leaves", e.parameter.userId);
      case 'submitCorrection':
        return saveToSheet("Corrections", JSON.parse(e.postData.contents));
      case 'getCorrections':
        return getDataByUserId("Corrections", e.parameter.userId);
      case 'getAnnouncements':
