  return createResponse(null);
}

function registerUser(user) {
  const sheet = SS.getSheetByName("Users");
  const id = "U-" + Math.floor(Math.random() * 1000000).toString();
  // Header: ID, Email, Name, Role, Department, Password
  sheet.appendRow([id, user.email, user.name, "employee", user.department, "123456"]);
  return createResponse({ id, ...user, role: "employee" });
}

function saveAttendance(record) {
  const sheet = SS.getSheetByName("Attendance");
  const id = "ATT-" + Utilities.getUuid().substring(0, 8);
  // Header: ID, UserID, Date, ClockIn, ClockOut, LatIn, LngIn, LatOut, LngOut, Status, SelfieIn, SelfieOut, WiFi
  sheet.appendRow([
    id, 
    record.userId, 
    record.date, 
    record.clockIn, 
    "", // ClockOut empty
    record.latIn, 
    record.lngIn, 
    "", // LatOut empty
    "", // LngOut empty
    record.status, 
    record.selfieIn, 
    "", // SelfieOut empty
    record.wifiVerified
  ]);
  return createResponse({ id, ...record });
}

function updateAttendance(update) {
  const sheet = SS.getSheetByName("Attendance");
  const data = sheet.getDataRange().getValues();

  for (let i = 1; i < data.length; i++) {
    // Cari record berdasarkan ID dan pastikan record hari ini
    if (data[i][0] === update.id) {
      sheet.getRange(i + 1, 5).setValue(update.clockOut);   // ClockOut
      sheet.getRange(i + 1, 8).setValue(update.latOut);     // LatOut
      sheet.getRange(i + 1, 9).setValue(update.lngOut);     // LngOut
      sheet.getRange(i + 1, 12).setValue(update.selfieOut); // SelfieOut
      return createResponse({ success: true });
