function saveToSheet(sheetName, data) {
  const sheet = SS.getSheetByName(sheetName);
  const id = "REQ-" + Utilities.getUuid().substring(0, 8);

  const headers = sheet.getDataRange().getValues()[0];
  const newRow = [id];

  // Mapping data based on keys to headers
  // Headers are: ID, UserID, ... (rest of data) ..., Status
  headers.slice(1, -1).forEach(h => {
    newRow.push(data[h.charAt(0).toLowerCase() + h.slice(1).replace(/\s+/g, '')] || "");
  });
  newRow.push("pending"); // Default status

  sheet.appendRow(newRow);
  return createResponse({ id, ...data, status: "pending" });
}

function getDataByUserId(sheetName, userId) {
  const sheet = SS.getSheetByName(sheetName);
