const GAS_URL = 'https://script.google.com/macros/s/AKfycbzi0ztfXk-49DBrwzlWuA4jR5ccrNQW7yxh4ppEgKV24SusVuehluWGtwZIuo7bfqStZg/exec';

class GasService {
  private async callGas(action: string, method: 'GET' | 'POST', body?: any, params: Record<string, string> = {}) {
    // Tambahkan action ke params
    const queryParams = new URLSearchParams({ action, ...params });
    const url = `${GAS_URL}?${queryParams.toString()}`;

    try {
      const options: RequestInit = {
        method: method,
        mode: 'cors',
      };

      if (method === 'POST' && body) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(url, options);
      return await response.json();
    } catch (error) {
      console.error(`GAS Service Error (${action}):`, error);
      return null;
    }
  }

  async login(email: string): Promise<User | null> {
    return await this.callGas('login', 'GET', null, { email });
  }

  async register(userData: Partial<User>): Promise<User> {
    const data = await this.callGas('register', 'POST', userData);
    return data || { ...userData, id: Math.random().toString(36).substr(2, 9) };
  }

  async submitAttendance(record: Partial<AttendanceRecord>): Promise<AttendanceRecord> {
    const data = await this.callGas('submitAttendance', 'POST', record);
    return data || record;
  }

  async updateAttendance(id: string, update: Partial<AttendanceRecord>): Promise<void> {
    await this.callGas('updateAttendance', 'POST', { id, ...update });
  }

  async getAttendance(userId?: string): Promise<AttendanceRecord[]> {
    const data = await this.callGas('getAttendance', 'GET', null, userId ? { userId } : {});
    return data || [];
  }

  async submitLeave(leave: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const data = await this.callGas('submitLeave', 'POST', leave);
    return data || leave;
  }

  async getLeaves(userId?: string): Promise<LeaveRequest[]> {
    const data = await this.callGas('getLeaves', 'GET', null, userId ? { userId } : {});
    return data || [];
  }

  async submitCorrection(data: Partial<CorrectionRequest>): Promise<CorrectionRequest> {
    const res = await this.callGas('submitCorrection', 'POST', data);
    return res || data;
  }

  async getCorrections(userId?: string): Promise<CorrectionRequest[]> {
    const data = await this.callGas('getCorrections', 'GET', null, userId ? { userId } : {});
    return data || [];
  }

  async getAnnouncements(): Promise<Announcement[]> {
    const data = await this.callGas('getAnnouncements', 'GET');
    return data || [];
  }

  async getSchedules(): Promise<WorkSchedule[]> {
    return [
      { day: 'Senin - Jumat', shift: 'Reguler', timeStart: '08:00', timeEnd: '17:00' },
      { day: 'Sabtu', shift: 'Setengah Hari', timeStart: '08:00', timeEnd: '12:00' }
    ];
  }
}

export const gasService = new GasService();

import React, { useState, useRef, useEffect } from 'react';
import { User, AttendanceRecord } from '../types';
import { gasService } from '../services/gasService';
import { verifyFace } from '../services/geminiService';

interface AttendanceProps {
  user: User;
  onBack: () => void;
}

const Attendance: React.FC<AttendanceProps> = ({ user, onBack }) => {
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<'camera' | 'verifying' | 'result'>('camera');
  const [photo, setPhoto] = useState<string | null>(null);
  const [location, setLocation] = useState<{lat: number, lng: number} | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<string | null>(null);
  const [todayRecord, setTodayRecord] = useState<AttendanceRecord | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    startCamera();
    getGeolocation();
    checkTodayStatus();
    return () => stopCamera();
  }, []);

  const checkTodayStatus = async () => {
    const records = await gasService.getAttendance(user.id);
    const today = new Date().toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' }).split('/').join('/');
    // GAS format: dd/MM/yyyy
    const todayRec = records.find(r => r.date === today);
    if (todayRec) setTodayRecord(todayRec);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("Kamera tidak dapat diakses.");
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
  };

  const getGeolocation = () => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        () => setError("Izin lokasi diperlukan.")
      );
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);
        setPhoto(dataUrl);
        processAttendance(dataUrl);
      }
    }
  };

  const processAttendance = async (capturedPhoto: string) => {
    setStep('verifying');
    setLoading(true);

    if (!location) {
      setError("Lokasi tidak ditemukan. Harap aktifkan GPS.");
      setStep('camera');
      setLoading(false);
      return;
    }

    const faceCheck = await verifyFace(capturedPhoto);
    if (!faceCheck.isVerified) {
      setError(`Verifikasi gagal: ${faceCheck.message}`);
      setStep('camera');
      setLoading(false);
      return;
    }

    try {
      const now = new Date();
      const timeStr = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
      const dateStr = now.toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' }).split('/').join('/');

      if (!todayRecord) {
        // Clock In
        const limit = new Date();
        limit.setHours(8, 30, 0);
        const status = now > limit ? 'terlambat' : 'hadir';

        await gasService.submitAttendance({
          userId: user.id,
          userName: user.name,
          date: dateStr,
          clockIn: timeStr,
          latIn: location.lat,
          lngIn: location.lng,
          selfieIn: capturedPhoto,
          status,
          wifiVerified: true
        });
        setResult(`Berhasil Clock-In pada ${timeStr}`);
      } else {
        // Clock Out
        await gasService.updateAttendance(todayRecord.id, {
          clockOut: timeStr,
          latOut: location.lat,
          lngOut: location.lng,
          selfieOut: capturedPhoto
        });
        setResult(`Berhasil Clock-Out pada ${timeStr}`);
      }
      setStep('result');
    } catch (err) {
      setError("Gagal menyimpan data presensi.");
      setStep('camera');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto px-4 pb-12">
      <div className="flex items-center gap-4 mb-6">
        <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-full">
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <h1 className="text-xl font-bold">Presensi Kehadiran</h1>
      </div>

      {step === 'camera' && (
        <div className="space-y-6">
          <div className="relative aspect-[3/4] bg-slate-900 rounded-3xl overflow-hidden shadow-2xl border-4 border-white">
            <video ref={videoRef} autoPlay playsInline className="absolute inset-0 w-full h-full object-cover" />
            <canvas ref={canvasRef} className="hidden" />

            <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
              <div className="w-64 h-80 border-2 border-white/50 border-dashed rounded-[100px] flex flex-col items-center justify-center bg-white/5">
                <span className="text-white/70 text-[10px] uppercase font-bold mt-auto mb-12">Posisikan Wajah Di Sini</span>
              </div>
            </div>

            <div className="absolute top-4 left-4 right-4 flex justify-between gap-2">
              <div className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase flex items-center gap-1 shadow-md ${location ? 'bg-green-500 text-white' : 'bg-red-500 text-white'}`}>
                <div className={`w-2 h-2 rounded-full bg-white ${!location && 'animate-pulse'}`} />
                {location ? 'GPS Aktif' : 'GPS Mati'}
              </div>
              <div className="px-3 py-1 rounded-full bg-blue-500 text-white text-[10px] font-bold uppercase flex items-center gap-1 shadow-md">
                <div className="w-2 h-2 rounded-full bg-white" />
                WiFi Kantor OK
              </div>
            </div>
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 p-4 rounded-2xl text-sm border border-red-100 flex items-start gap-3">
              <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd"></path></svg>
              {error}
            </div>
          )}

          <div className="p-4 bg-white rounded-2xl border shadow-sm">
            <h3 className="font-bold text-slate-800 mb-1">Status Hari Ini</h3>
            <p className="text-xs text-slate-500">
              {todayRecord 
                ? todayRecord.clockOut 
                  ? "Anda sudah melakukan Clock-In dan Clock-Out hari ini."
                  : `Sudah Clock-In pukul ${todayRecord.clockin}. Sekarang lakukan Clock-Out.` 
                : 'Belum melakukan presensi. Silakan tekan tombol di bawah.'}
            </p>
          </div>

          <button
            disabled={!location || loading || (todayRecord && todayRecord.clockout)}
            onClick={capturePhoto}
