Ganti seluruh isi file `gas_code.gs` di Google Apps Script Anda dengan kode di bawah ini. Kode ini telah saya perbaiki secara total untuk memastikan sinkronisasi antara ID, UserID, dan koordinat lokasi (Lat/Lng) saat Clock Out.

### 1. Update `gas_code.gs` (Ganti Semua Isinya)

```javascript
/**
 * PresensiGo - Google Apps Script Backend (Production Ready)
 * 
 * SETUP:
 * Deploy sebagai Web App: 
 * - Execute as: Me
 * - Who has access: Anyone
 */

const SS = SpreadsheetApp.getActiveSpreadsheet();

function doGet(e) {
  const action = e.parameter.action;
  const userId = e.parameter.userId;

  try {
    switch (action) {
      case 'login':
        return loginUser(e.parameter.email);
      case 'getAttendance':
        return getDataByUserId("Attendance", userId);
      case 'getLeaves':
        return getDataByUserId("Leaves", userId);
      case 'getCorrections':
        return getDataByUserId("Corrections", userId);
      case 'getAnnouncements':
        return getAllData("Announcements");
      default:
        return createResponse({ error: "Action doGet tidak ditemukan" });
    }
  } catch (err) {
    return createResponse({ error: err.toString() });
  }
}

function doPost(e) {
  let postData;
  try {
    postData = JSON.parse(e.postData.contents);
  } catch (f) {
    return createResponse({ error: "Format JSON tidak valid" });
  }

  const action = e.parameter.action;

  try {
    switch (action) {
      case 'register':
        return registerUser(postData);
      case 'submitAttendance':
        return saveAttendance(postData);
      case 'updateAttendance':
        return updateAttendance(postData);
      case 'submitLeave':
        return saveToSheet("Leaves", postData);
      case 'submitCorrection':
        return saveToSheet("Corrections", postData);
      default:
        return createResponse({ error: "Action doPost tidak ditemukan" });
    }
  } catch (err) {
    return createResponse({ error: err.toString() });
  }
}

function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function loginUser(email) {
  const sheet = SS.getSheetByName("Users");
  const data = sheet.getDataRange().getValues();
  const headers = data[0].map(h => h.toString().toLowerCase());

  for (let i = 1; i < data.length; i++) {
    if (data[i][1].toString().toLowerCase() === email.toLowerCase()) {
      let userObj = {};
      headers.forEach((h, idx) => userObj[h] = data[i][idx]);
      return createResponse(userObj);
    }
  }
  return createResponse(null);
}

function registerUser(user) {
  const sheet = SS.getSheetByName("Users");
  const id = "U-" + Math.floor(Math.random() * 1000000).toString();
  sheet.appendRow([id, user.email, user.name, "employee", user.department, "123456"]);
  return createResponse({ id, ...user, role: "employee" });
}

function saveAttendance(record) {
  const sheet = SS.getSheetByName("Attendance");
  const id = "ATT-" + Utilities.getUuid().substring(0, 8);
  const today = Utilities.formatDate(new Date(), "GMT+7", "dd/MM/yyyy");
  const dateToSave = record.date || today;

  // Pastikan record.userId ada dan diubah ke string
  const uid = record.userId ? record.userId.toString() : "";

  // Header: ID, UserID, Date, ClockIn, ClockOut, LatIn, LngIn, LatOut, LngOut, Status, SelfieIn, SelfieOut, WiFi
  sheet.appendRow([
    id, 
    uid, 
    dateToSave, 
    record.clockIn || "", 
    "", // ClockOut empty
    record.latIn || "", 
    record.lngIn || "", 
    "", // LatOut empty
    "", // LngOut empty
    record.status || "hadir", 
    record.selfieIn || "", 
    "", // SelfieOut empty
    record.wifiVerified || false
  ]);
  return createResponse({ id, ...record, date: dateToSave });
}

function updateAttendance(update) {
  const sheet = SS.getSheetByName("Attendance");
  const data = sheet.getDataRange().getValues();

  for (let i = 1; i < data.length; i++) {
    // Cari baris berdasarkan ID Attendance unik
    if (data[i][0].toString() === update.id.toString()) {
      // Index dimulai dari 1 (Kolom A=1, B=2, dst)
      sheet.getRange(i + 1, 5).setValue(update.clockOut || "");   // Column E: ClockOut
      sheet.getRange(i + 1, 8).setValue(update.latOut || "");     // Column H: LatOut
      sheet.getRange(i + 1, 9).setValue(update.lngOut || "");     // Column I: LngOut
      sheet.getRange(i + 1, 12).setValue(update.selfieOut || ""); // Column L: SelfieOut
      return createResponse({ success: true, id: update.id });
    }
  }
  return createResponse({ success: false, message: "Record tidak ditemukan" });
}

function saveToSheet(sheetName, data) {
  const sheet = SS.getSheetByName(sheetName);
  const id = "REQ-" + Utilities.getUuid().substring(0, 8);
  let newRow = [id];

  if (sheetName === "Leaves") {
    newRow.push(data.userId.toString(), data.userName, data.type, data.startDate, data.endDate, data.reason, "pending");
  } else if (sheetName === "Corrections") {
    newRow.push(data.userId.toString(), data.date, data.requestedTime, data.reason, "pending");
  }

  sheet.appendRow(newRow);
  return createResponse({ id, ...data, status: "pending" });
}

function getDataByUserId(sheetName, userId) {
  const sheet = SS.getSheetByName(sheetName);
  if (!sheet) return createResponse([]);
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return createResponse([]);
  const headers = data[0].map(h => h.toString().toLowerCase());
  const results = [];

  for (let i = 1; i < data.length; i++) {
    // UserID biasanya di Kolom B (Index 1)
    if (userId && data[i][1].toString() === userId.toString()) {
      let obj = {};
      headers.forEach((h, idx) => obj[h] = data[i][idx]);
      results.push(obj);
    } else if (!userId) {
      let obj = {};
      headers.forEach((h, idx) => obj[h] = data[i][idx]);
      results.push(obj);
    }
  }
  return createResponse(results);
}

function getAllData(sheetName) {
  const sheet = SS.getSheetByName(sheetName);
  if (!sheet) return createResponse([]);
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return createResponse([]);
  const headers = data[0].map(h => h.toString().toLowerCase());
  const results = [];

  for (let i = 1; i < data.length; i++) {
    let obj = {};
    headers.forEach((h, idx) => obj[h] = data[i][idx]);
    results.push(obj);
  }
  return createResponse(results);
}
```

