/**
 * GANTI URL DI BAWAH INI dengan URL Web App dari Google Apps Script Anda
 */
const GAS_URL = 'https://script.google.com/macros/s/AKfycbzi0ztfXk-49DBrwzlWuA4jR5ccrNQW7yxh4ppEgKV24SusVuehluWGtwZIuo7bfqStZg/exec';

class GasService {
  private async callGas(action: string, method: 'GET' | 'POST', body?: any, params: Record<string, string> = {}) {
    const queryParams = new URLSearchParams({ action, ...params });
    const url = `${GAS_URL}?${queryParams.toString()}`;

    try {
      const options: RequestInit = {
        method: method,
        mode: 'cors',
      };

      if (method === 'POST' && body) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(url, options);
      if (!response.ok) throw new Error('Network response was not ok');
      return await response.json();
    } catch (error) {
      console.error(`GAS Service Error (${action}):`, error);
      return null;
    }
  }

  async login(email: string): Promise<User | null> {
    const data = await this.callGas('login', 'GET', null, { email });
    return (data && !data.error) ? data : null;
  }

  async register(userData: Partial<User>): Promise<User> {
    const data = await this.callGas('register', 'POST', userData);
    return data || { ...userData, id: Math.random().toString(36).substr(2, 9) };
  }

  async submitAttendance(record: Partial<AttendanceRecord>): Promise<AttendanceRecord> {
    const data = await this.callGas('submitAttendance', 'POST', record);
    return data || record;
  }

  async updateAttendance(id: string, update: Partial<AttendanceRecord>): Promise<void> {
    await this.callGas('updateAttendance', 'POST', { id, ...update });
  }

  async getAttendance(userId?: string): Promise<AttendanceRecord[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getAttendance', 'GET', null, params);
    return Array.isArray(data) ? data : [];
  }

  async submitLeave(leave: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const data = await this.callGas('submitLeave', 'POST', leave);
    return data || leave;
  }

  async getLeaves(userId?: string): Promise<LeaveRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getLeaves', 'GET', null, params);
    return Array.isArray(data) ? data : [];
  }

  async submitCorrection(data: Partial<CorrectionRequest>): Promise<CorrectionRequest> {
    const res = await this.callGas('submitCorrection', 'POST', data);
    return res || data;
  }

  async getCorrections(userId?: string): Promise<CorrectionRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getCorrections', 'GET', null, params);
    return Array.isArray(data) ? data : [];
  }

  async getAnnouncements(): Promise<Announcement[]> {
    const data = await this.callGas('getAnnouncements', 'GET');
    return Array.isArray(data) ? data : [];
  }

  async getSchedules(): Promise<WorkSchedule[]> {
    return [
      { day: 'Senin - Jumat', shift: 'Reguler', timeStart: '08:00', timeEnd: '17:00' },
      { day: 'Sabtu', shift: 'Setengah Hari', timeStart: '08:00', timeEnd: '12:00' }
    ];
  }

  // Admin specific methods
  async getAllUsers(): Promise<User[]> {
    const data = await this.callGas('getAllUsers', 'GET');
    return Array.isArray(data) ? data : [];
  }

  async updateRequestStatus(type: 'leave' | 'correction', id: string, status: 'approved' | 'rejected'): Promise<boolean> {
    const res = await this.callGas('updateRequestStatus', 'POST', { type, id, status });
    return !!(res && res.success);
  }

  async addAnnouncement(announcement: Partial<Announcement>): Promise<boolean> {
    const res = await this.callGas('addAnnouncement', 'POST', announcement);
    return !!(res && res.success);
  }
}

