/**
 * PresensiGo - Google Apps Script Backend
 */

const SS = SpreadsheetApp.getActiveSpreadsheet();

function doGet(e) {
  const action = e.parameter.action;
  const userId = e.parameter.userId;

  try {
    switch (action) {
      case 'login':
        return loginUser(e.parameter.email);
      case 'getAttendance':
        return getDataByUserId("Attendance", userId);
      case 'getLeaves':
        return getDataByUserId("Leaves", userId);
      case 'getCorrections':
        return getDataByUserId("Corrections", userId);
      case 'getAnnouncements':
        return getAllData("Announcements");
      case 'getAllUsers':
        return getAllData("Users");
      case 'getSettings':
        return getSettings();
      default:
        return createResponse({ error: "Action doGet tidak ditemukan" });
    }
  } catch (err) {
    return createResponse({ error: err.toString() });
  }
}

function doPost(e) {
  let postData;
  try {
    postData = JSON.parse(e.postData.contents);
  } catch (f) {
    return createResponse({ error: "Format JSON tidak valid" });
  }

  const action = e.parameter.action;

  try {
    switch (action) {
      case 'register':
        return registerUser(postData);
      case 'submitAttendance':
        return saveAttendance(postData);
      case 'updateAttendance':
        return updateAttendance(postData);
      case 'submitLeave':
        return saveToSheet("Leaves", postData);
      case 'submitCorrection':
        return saveToSheet("Corrections", postData);
      case 'updateRequestStatus':
        return updateRequestStatus(postData);
      case 'addAnnouncement':
        return addAnnouncement(postData);
      case 'updateSettings':
        return updateSettings(postData);
      default:
        return createResponse({ error: "Action doPost tidak ditemukan" });
    }
  } catch (err) {
    return createResponse({ error: err.toString() });
  }
}

function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

// --- Logic Functions ---

function getSettings() {
  const sheet = SS.getSheetByName("Settings") || SS.insertSheet("Settings");
  const data = sheet.getDataRange().getValues();
  let settings = {
    office_lat: -6.2000,
    office_lng: 106.8166,
    attendance_radius: 100
  };

  if (data.length > 1) {
    for (let i = 1; i < data.length; i++) {
      settings[data[i][0]] = data[i][1];
    }
  } else {
    // Init default settings if empty
    sheet.appendRow(["Key", "Value"]);
    sheet.appendRow(["office_lat", -6.2000]);
    sheet.appendRow(["office_lng", 106.8166]);
    sheet.appendRow(["attendance_radius", 100]);
  }
  return createResponse(settings);
}

function updateSettings(settings) {
  const sheet = SS.getSheetByName("Settings");
  const data = sheet.getDataRange().getValues();

  for (let key in settings) {
    let found = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] === key) {
        sheet.getRange(i + 1, 2).setValue(settings[key]);
        found = true;
        break;
      }
    }
    if (!found) {
      sheet.appendRow([key, settings[key]]);
    }
  }
  return createResponse({ success: true });
}

function loginUser(email) {
  const sheet = SS.getSheetByName("Users");
  const data = sheet.getDataRange().getValues();
  const headers = data[0].map(h => h.toString().toLowerCase());

  for (let i = 1; i < data.length; i++) {
    if (data[i][1].toString().toLowerCase() === email.toLowerCase()) {
      let userObj = {};
      headers.forEach((h, idx) => userObj[h] = data[i][idx]);
      return createResponse(userObj);
    }
  }
  return createResponse(null);
}

function registerUser(user) {
  const sheet = SS.getSheetByName("Users");
  const id = "U-" + Math.floor(Math.random() * 1000000).toString();
  sheet.appendRow([id, user.email, user.name, "employee", user.department, "123456", user.faceData]);
  return createResponse({ id, ...user, role: "employee" });
}

function saveAttendance(record) {
  const sheet = SS.getSheetByName("Attendance");
  const id = "ATT-" + Utilities.getUuid().substring(0, 8);
  const today = Utilities.formatDate(new Date(), "GMT+7", "dd/MM/yyyy");
  const dateToSave = record.date || today;

  sheet.appendRow([
    id, record.userId.toString(), dateToSave, record.clockIn || "", "", 
    record.latIn || "", record.lngIn || "", "", "", 
    record.status || "hadir", record.selfieIn || "", "", record.wifiVerified || false
  ]);
  return createResponse({ id, ...record, date: dateToSave });
}

function updateAttendance(update) {
  const sheet = SS.getSheetByName("Attendance");
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0].toString() === update.id.toString()) {
      sheet.getRange(i + 1, 5).setValue(update.clockOut || "");
      sheet.getRange(i + 1, 8).setValue(update.latOut || "");
      sheet.getRange(i + 1, 9).setValue(update.lngOut || "");
      sheet.getRange(i + 1, 12).setValue(update.selfieOut || "");
      return createResponse({ success: true, id: update.id });
    }
  }
  return createResponse({ success: false });
}

function saveToSheet(sheetName, data) {
  const sheet = SS.getSheetByName(sheetName);
  const id = "REQ-" + Utilities.getUuid().substring(0, 8);
  let newRow = [id];
  if (sheetName === "Leaves") {
    newRow.push(data.userId.toString(), data.userName, data.type, data.startDate, data.endDate, data.reason, "pending");
  } else if (sheetName === "Corrections") {
    newRow.push(data.userId.toString(), data.date, data.requestedTime, data.reason, "pending");
  }
  sheet.appendRow(newRow);
  return createResponse({ id, ...data, status: "pending" });
}

function updateRequestStatus(update) {
  const sheetName = update.type === 'leave' ? 'Leaves' : 'Corrections';
  const sheet = SS.getSheetByName(sheetName);
  const data = sheet.getDataRange().getValues();
  const statusCol = sheetName === 'Leaves' ? 8 : 6;
  for (let i = 1; i < data.length; i++) {
    if (data[i][0].toString() === update.id.toString()) {
      sheet.getRange(i + 1, statusCol).setValue(update.status);
      return createResponse({ success: true });
    }
  }
  return createResponse({ success: false });
}

function addAnnouncement(ann) {
  const sheet = SS.getSheetByName("Announcements");
  const id = "ANN-" + Utilities.getUuid().substring(0, 8);
  const date = Utilities.formatDate(new Date(), "GMT+7", "dd/MM/yyyy HH:mm");
  sheet.appendRow([id, ann.title, ann.content, date, ann.author]);
  return createResponse({ success: true });
}

function getDataByUserId(sheetName, userId) {
  const sheet = SS.getSheetByName(sheetName);
  if (!sheet) return createResponse([]);
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return createResponse([]);
  const headers = data[0].map(h => h.toString().toLowerCase());
  const results = [];
  for (let i = 1; i < data.length; i++) {
    if (!userId || data[i][1].toString() === userId.toString()) {
      let obj = {};
      headers.forEach((h, idx) => obj[h] = data[i][idx]);
      results.push(obj);
    }
  }
  return createResponse(results);
}

function getAllData(sheetName) {
  const sheet = SS.getSheetByName(sheetName);
  if (!sheet) return createResponse([]);
  const data = sheet.getDataRange().getValues();
  const headers = data[0].map(h => h.toString().toLowerCase());
  const results = [];
  for (let i = 1; i < data.length; i++) {
    let obj = {};
    headers.forEach((h, idx) => obj[h] = data[i][idx]);
    results.push(obj);
  }
  return createResponse(results);
}

import { User, AttendanceRecord, LeaveRequest, Announcement, CorrectionRequest, WorkSchedule } from '../types';

/**
 * GANTI URL DI BAWAH INI dengan URL Web App dari Google Apps Script Anda
 */
const GAS_URL = 'https://script.google.com/macros/s/AKfycbzi0ztfXk-49DBrwzlWuA4jR5ccrNQW7yxh4ppEgKV24SusVuehluWGtwZIuo7bfqStZg/exec';

class GasService {
  private async callGas(action: string, method: 'GET' | 'POST', body?: any, params: Record<string, string> = {}) {
    const queryParams = new URLSearchParams({ action, ...params });
    const url = `${GAS_URL}?${queryParams.toString()}`;

    try {
      const options: RequestInit = {
        method: method,
        mode: 'cors',
      };

      if (method === 'POST' && body) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(url, options);
      if (!response.ok) throw new Error('Network response was not ok');
      return await response.json();
    } catch (error) {
      console.error(`GAS Service Error (${action}):`, error);
      return null;
    }
  }

  async login(email: string): Promise<User | null> {
    const data = await this.callGas('login', 'GET', null, { email });
    return (data && !data.error) ? data : null;
  }

  async register(userData: Partial<User>): Promise<User> {
    const data = await this.callGas('register', 'POST', userData);
    return data || { ...userData, id: Math.random().toString(36).substr(2, 9) };
  }

  async submitAttendance(record: Partial<AttendanceRecord>): Promise<AttendanceRecord> {
    const data = await this.callGas('submitAttendance', 'POST', record);
    return data || record;
  }

  async updateAttendance(id: string, update: Partial<AttendanceRecord>): Promise<void> {
    await this.callGas('updateAttendance', 'POST', { id, ...update });
  }

  async getAttendance(userId?: string): Promise<AttendanceRecord[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getAttendance', 'GET', null, params);
    return Array.isArray(data) ? data : [];
  }

  async submitLeave(leave: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const data = await this.callGas('submitLeave', 'POST', leave);
    return data || leave;
  }

  async getLeaves(userId?: string): Promise<LeaveRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getLeaves', 'GET', null, params);
    return Array.isArray(data) ? data : [];
  }

  async submitCorrection(data: Partial<CorrectionRequest>): Promise<CorrectionRequest> {
    const res = await this.callGas('submitCorrection', 'POST', data);
    return res || data;
  }

  async getCorrections(userId?: string): Promise<CorrectionRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getCorrections', 'GET', null, params);
    return Array.isArray(data) ? data : [];
  }

  async getAnnouncements(): Promise<Announcement[]> {
    const data = await this.callGas('getAnnouncements', 'GET');
    return Array.isArray(data) ? data : [];
  }

  async getSchedules(): Promise<WorkSchedule[]> {
    return [
      { day: 'Senin - Jumat', shift: 'Reguler', timeStart: '08:00', timeEnd: '17:00' },
      { day: 'Sabtu', shift: 'Setengah Hari', timeStart: '08:00', timeEnd: '12:00' }
    ];
  }

  // Admin specific methods
  async getAllUsers(): Promise<User[]> {
    const data = await this.callGas('getAllUsers', 'GET');
    return Array.isArray(data) ? data : [];
  }

  async updateRequestStatus(type: 'leave' | 'correction', id: string, status: 'approved' | 'rejected'): Promise<boolean> {
    const res = await this.callGas('updateRequestStatus', 'POST', { type, id, status });
    return !!(res && res.success);
  }

  async addAnnouncement(announcement: Partial<Announcement>): Promise<boolean> {
    const res = await this.callGas('addAnnouncement', 'POST', announcement);
    return !!(res && res.success);
  }

  async getSettings(): Promise<any> {
    return await this.callGas('getSettings', 'GET');
  }

  async updateSettings(settings: any): Promise<boolean> {
    const res = await this.callGas('updateSettings', 'POST', settings);
    return !!(res && res.success);
  }
}

export const gasService = new GasService();

