                           <span className="text-[10px] bg-indigo-50 text-indigo-600 font-bold px-2 py-0.5 rounded-full uppercase">{l.type}</span>
                        </div>
                        <p className="text-xs text-slate-500 mt-1">{l.startDate} s/d {l.endDate}</p>
                        <p className="text-sm text-slate-600 mt-2 bg-slate-50 p-3 rounded-2xl italic">"{l.reason}"</p>
                      </div>
                      <div className="flex gap-2">
                        <button onClick={() => handleUpdateStatus('leave', l.id, 'approved')} className="bg-green-600 text-white px-4 py-2 rounded-xl text-xs font-bold hover:bg-green-700">Setujui</button>
                        <button onClick={() => handleUpdateStatus('leave', l.id, 'rejected')} className="bg-red-50 text-red-600 px-4 py-2 rounded-xl text-xs font-bold hover:bg-red-100">Tolak</button>
                      </div>
                    </div>
                  ))}
                  {(!Array.isArray(leaves) || leaves.filter(l => l.status === 'pending').length === 0) && <p className="text-center text-slate-400 py-10">Tidak ada pengajuan izin baru.</p>}
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

