  const downloadRecap = () => {
    if (!Array.isArray(attendance) || attendance.length === 0) {
      alert("Tidak ada data untuk diunduh");
      return;
    }
    const headers = ["ID", "User ID", "Tanggal", "Clock In", "Clock Out", "Lat In", "Lng In", "Lat Out", "Lng Out", "Status", "WiFi"];
    const csvContent = [
      headers.join(","),
      ...attendance.map(row => [
        row.id, row.userId, row.date, row.clockIn, row.clockOut || "-",
        row.latIn, row.lngIn, row.latOut || "-", row.lngOut || "-",
