import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Verifikasi wajah baru (Saat Registrasi)
 */
export const analyzeEnrollmentFace = async (base64Image: string): Promise<{ isVerified: boolean; message: string }> => {
  try {
    // Use gemini-3-pro-preview for complex reasoning tasks like face verification
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
          { text: "Apakah ini foto wajah manusia yang jelas untuk pendaftaran absensi? Wajah harus terlihat penuh dan tidak terhalang. Jawab dalam JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isFace: { type: Type.BOOLEAN },
            message: { type: Type.STRING }
          },
          required: ['isFace', 'message'],
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return {
      isVerified: result.isFace || false,
      message: result.message || "Gagal menganalisis wajah."
    };
  } catch (error) {
    return { isVerified: false, message: "Kesalahan sistem analisis wajah." };
  }
};

/**
 * Pencocokan Wajah (Saat Presensi)
 */
export const matchFace = async (registeredFace: string, currentSelfie: string): Promise<{ isMatch: boolean; confidence: number; message: string }> => {
  try {
    // Use gemini-3-pro-preview for high-accuracy multimodal tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: registeredFace.split(',')[1], mimeType: 'image/jpeg' } }, // Foto Master
          { inlineData: { data: currentSelfie.split(',')[1], mimeType: 'image/jpeg' } },   // Foto Sekarang
          { text: "Bandingkan dua foto ini. Foto 1 adalah wajah terdaftar. Foto 2 adalah orang yang mencoba absen. Apakah mereka orang yang sama? Berikan skor kepercayaan (0-1). Jawab dalam JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isMatch: { type: Type.BOOLEAN },
            confidence: { type: Type.NUMBER },
            message: { type: Type.STRING }
          },
          required: ['isMatch', 'confidence', 'message'],
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return {
      isMatch: (result.isMatch && result.confidence > 0.75) || false,
      confidence: result.confidence || 0,
      message: result.message || "Pencocokan gagal."
    };
  } catch (error) {
    return { isMatch: false, confidence: 0, message: "Kesalahan sistem pencocokan wajah." };
  }
};

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, Announcement, CorrectionRequest } from '../types';
import { gasService } from '../services/gasService';

interface AdminDashboardProps {
  user: User;
  onBack: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user, onBack }) => {
  const [tab, setTab] = useState<'users' | 'attendance' | 'requests' | 'announcements' | 'settings'>('users');
  const [users, setUsers] = useState<User[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>([]);
  const [corrections, setCorrections] = useState<CorrectionRequest[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const [newAnn, setNewAnn] = useState({ title: '', content: '' });
  const [settings, setSettings] = useState({
    office_lat: -6.2000,
    office_lng: 106.8166,
    attendance_radius: 100
  });

  useEffect(() => {
    fetchAllData();
  }, []);

  const fetchAllData = async () => {
    setLoading(true);
    try {
      const [u, a, l, c, ann, s] = await Promise.all([
        gasService.getAllUsers(),
        gasService.getAttendance(),
        gasService.getLeaves(),
        gasService.getCorrections(),
        gasService.getAnnouncements(),
        gasService.getSettings()
      ]);
      setUsers(u);
      setAttendance(a);
      setLeaves(l);
      setCorrections(c);
      setAnnouncements(ann);
      if (s && !s.error) {
        setSettings({
          office_lat: parseFloat(s.office_lat) || -6.2000,
          office_lng: parseFloat(s.office_lng) || 106.8166,
          attendance_radius: parseInt(s.attendance_radius) || 100
        });
      }
    } catch (error) {
      console.error("Error fetching admin data:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateStatus = async (type: 'leave' | 'correction', id: string, status: 'approved' | 'rejected') => {
    const success = await gasService.updateRequestStatus(type, id, status);
    if (success) {
      alert("Status berhasil diperbarui");
      fetchAllData();
    }
  };

  const handleAddAnnouncement = async (e: React.FormEvent) => {
    e.preventDefault();
    const success = await gasService.addAnnouncement({ ...newAnn, author: user.name });
    if (success) {
      setNewAnn({ title: '', content: '' });
      alert("Pengumuman dipublikasikan");
      fetchAllData();
    }
  };

  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingSettings(true);
    try {
      const success = await gasService.updateSettings(settings);
      if (success) {
        alert("Konfigurasi kantor berhasil diperbarui di database!");
        // Re-fetch to confirm
        const s = await gasService.getSettings();
        if (s && !s.error) {
          setSettings({
            office_lat: parseFloat(s.office_lat),
            office_lng: parseFloat(s.office_lng),
            attendance_radius: parseInt(s.attendance_radius)
          });
        }
      } else {
        alert("Gagal memperbarui pengaturan. Periksa koneksi atau URL GAS Anda.");
      }
    } catch (error) {
      alert("Terjadi kesalahan saat menyimpan pengaturan.");
      console.error(error);
    } finally {
      setIsSavingSettings(false);
    }
  };

  const getCurrentLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((pos) => {
        setSettings({
          ...settings,
          office_lat: pos.coords.latitude,
          office_lng: pos.coords.longitude
        });
      }, () => alert("Gagal mendapatkan lokasi. Pastikan izin GPS aktif."));
    }
  };

  const downloadRecap = () => {
    if (!Array.isArray(attendance) || attendance.length === 0) {
      alert("Tidak ada data untuk diunduh");
      return;
    }
