                      value={settings.office_lng}
                      onChange={e => setSettings({...settings, office_lng: parseFloat(e.target.value)})}
                    />
                  </div>
                </div>

                <button 
                  type="button"
                  onClick={getCurrentLocation}
                  className="w-full py-3 border-2 border-dashed border-slate-200 rounded-2xl text-slate-500 font-bold text-xs hover:bg-slate-50 transition-colors flex items-center justify-center gap-2"
                >
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  </svg>
                  Gunakan Lokasi Saya Saat Ini (Taging)
                </button>

                <div>
                  <label className="block text-[10px] font-bold text-slate-400 uppercase mb-2">Radius Presensi Maksimal (Meter)</label>
                  <input 
                    type="number" required
                    className="w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:ring-2 focus:ring-blue-500"
                    value={settings.attendance_radius}
                    onChange={e => setSettings({...settings, attendance_radius: parseInt(e.target.value)})}
                  />
                  <p className="text-[10px] text-slate-400 mt-2 italic">*Karyawan harus berada dalam radius {settings.attendance_radius}m dari titik koordinat di atas.</p>
                </div>

                <button 
                  type="submit" 
                  disabled={isSavingSettings}
                  className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all flex items-center justify-center gap-2"
                >
                  {isSavingSettings ? (
                    <>
                      <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                      Menyimpan...
                    </>
                  ) : "Simpan Pengaturan Kantor"}
                </button>
              </form>
            </div>
          )}

          {tab === 'announcements' && (
            <div className="grid md:grid-cols-2 gap-8">
              <div className="bg-white p-6 rounded-3xl border shadow-sm">
                <h3 className="font-bold text-slate-800 mb-6">Tambah Pengumuman Baru</h3>
                <form onSubmit={handleAddAnnouncement} className="space-y-4">
                  <div>
                    <label className="block text-[10px] font-bold text-slate-400 uppercase mb-2">Judul Pengumuman</label>
                    <input type="text" required className="w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:ring-2 focus:ring-blue-500" value={newAnn.title} onChange={e => setNewAnn({...newAnn, title: e.target.value})} />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-slate-400 uppercase mb-2">Isi Konten</label>
                    <textarea rows={4} required className="w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 resize-none" value={newAnn.content} onChange={e => setNewAnn({...newAnn, content: e.target.value})} />
                  </div>
                  <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-blue-100">Publikasikan Sekarang</button>
                </form>
              </div>
              <div className="space-y-4">
                <h3 className="font-bold text-slate-800">Riwayat Pengumuman</h3>
                {Array.isArray(announcements) && announcements.map(ann => (
                  <div key={ann.id} className="bg-white p-5 rounded-3xl border shadow-sm border-l-4 border-l-blue-500">
                    <h4 className="font-bold text-slate-800">{ann.title}</h4>
                    <p className="text-xs text-slate-500 mt-2 line-clamp-2">{ann.content}</p>
                    <div className="mt-4 flex justify-between items-center text-[10px] font-bold text-slate-400"><span>{ann.author}</span><span>{ann.date}</span></div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {tab === 'requests' && (
            <div className="grid md:grid-cols-2 gap-8">
              {/* Left Column: Leave Requests */}
              <div>
                <h3 className="font-bold text-slate-800 mb-4 px-2 flex items-center gap-2">
                  <svg className="w-5 h-5 text-indigo-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                  Persetujuan Izin & Cuti
                </h3>
                <div className="grid gap-4">
                  {Array.isArray(leaves) && leaves.filter(l => l.status === 'pending').map(l => (
                    <div key={l.id} className="bg-white p-5 rounded-3xl border shadow-sm transition-all hover:border-indigo-200">
                      <div>
                        <div className="flex items-center gap-2 justify-between mb-2">
                           <span className="font-bold text-slate-800">{l.userName}</span>
                           <span className="text-[10px] bg-indigo-50 text-indigo-600 font-bold px-2 py-0.5 rounded-full uppercase">{l.type}</span>
                        </div>
                        <p className="text-xs text-slate-500">{l.startDate} s/d {l.endDate}</p>
                        <p className="text-sm text-slate-600 mt-3 bg-slate-50 p-3 rounded-2xl italic">"{l.reason}"</p>
                      </div>
                      <div className="flex gap-2 mt-4">
                        <button onClick={() => handleUpdateStatus('leave', l.id, 'approved')} className="flex-1 bg-green-600 text-white py-2 rounded-xl text-xs font-bold hover:bg-green-700">Setujui</button>
                        <button onClick={() => handleUpdateStatus('leave', l.id, 'rejected')} className="flex-1 bg-red-50 text-red-600 py-2 rounded-xl text-xs font-bold hover:bg-red-100">Tolak</button>
                      </div>
                    </div>
                  ))}
                  {(!Array.isArray(leaves) || leaves.filter(l => l.status === 'pending').length === 0) && <p className="text-center text-slate-400 py-10 text-xs bg-white rounded-3xl border border-dashed">Tidak ada pengajuan izin baru.</p>}
                </div>
              </div>

              {/* Right Column: Correction Requests */}
              <div>
                <h3 className="font-bold text-slate-800 mb-4 px-2 flex items-center gap-2">
                  <svg className="w-5 h-5 text-orange-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                  Persetujuan Koreksi Absen
                </h3>
                <div className="grid gap-4">
                  {Array.isArray(corrections) && corrections.filter(c => c.status === 'pending').map(c => (
                    <div key={c.id} className="bg-white p-5 rounded-3xl border shadow-sm transition-all hover:border-orange-200">
                      <div>
                        <div className="flex items-center gap-2 justify-between mb-2">
                           <span className="font-bold text-slate-800">{getUserName(c.userId)}</span>
                           <span className="text-[10px] bg-orange-50 text-orange-600 font-bold px-2 py-0.5 rounded-full uppercase">Koreksi</span>
                        </div>
                        <p className="text-xs text-slate-500">Tanggal: {c.date} • Jam: {c.requestedTime}</p>
                        <p className="text-sm text-slate-600 mt-3 bg-slate-50 p-3 rounded-2xl italic">"{c.reason}"</p>
                      </div>
                      <div className="flex gap-2 mt-4">
                        <button onClick={() => handleUpdateStatus('correction', c.id, 'approved')} className="flex-1 bg-green-600 text-white py-2 rounded-xl text-xs font-bold hover:bg-green-700">Setujui</button>
                        <button onClick={() => handleUpdateStatus('correction', c.id, 'rejected')} className="flex-1 bg-red-50 text-red-600 py-2 rounded-xl text-xs font-bold hover:bg-red-100">Tolak</button>
                      </div>
                    </div>
                  ))}
                  {(!Array.isArray(corrections) || corrections.filter(c => c.status === 'pending').length === 0) && <p className="text-center text-slate-400 py-10 text-xs bg-white rounded-3xl border border-dashed">Tidak ada pengajuan koreksi baru.</p>}
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

export interface User {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'employee';
  department: string;
  profileImage?: string;
  faceData?: string; // Base64 master wajah saat registrasi
}

export interface AttendanceRecord {
  id: string;
  userId: string;
  userName: string;
  date: string;
  clockIn: string;
  clockOut?: string;
  latIn: number;
  lngIn: number;
  latOut?: number;
  lngOut?: number;
  status: 'hadir' | 'terlambat' | 'izin' | 'alpa' | 'sakit';
  selfieIn?: string;
  selfieOut?: string;
  wifiVerified: boolean;
}

export interface LeaveRequest {
  id: string;
  userId: string;
  userName: string;
  startDate: string;
  endDate: string;
  reason: string;
  status: 'pending' | 'approved' | 'rejected';
  type: 'cuti' | 'izin' | 'sakit';
}

export interface CorrectionRequest {
  id: string;
  attendanceId: string;
  userId: string;
  date: string;
  requestedTime: string;
  reason: string;
  status: 'pending' | 'approved' | 'rejected';
}

export interface Announcement {
  id: string;
  title: string;
  content: string;
  date: string;
  author: string;
}

export interface WorkSchedule {
  day: string;
  shift: string;
  timeStart: string;
  timeEnd: string;
}

export enum Page {
  LOGIN = 'LOGIN',
  REGISTER = 'REGISTER',
  DASHBOARD = 'DASHBOARD',
  ATTENDANCE = 'ATTENDANCE',
  LEAVE = 'LEAVE',
  REPORT = 'REPORT',
  CORRECTION = 'CORRECTION',
  PROFILE = 'PROFILE',
  ADMIN = 'ADMIN'
}

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, Announcement, CorrectionRequest } from '../types';
import { gasService } from '../services/gasService';

interface AdminDashboardProps {
  user: User;
  onBack: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user, onBack }) => {
  const [tab, setTab] = useState<'users' | 'attendance' | 'requests' | 'announcements' | 'settings'>('users');
  const [users, setUsers] = useState<User[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>([]);
  const [corrections, setCorrections] = useState<CorrectionRequest[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const [newAnn, setNewAnn] = useState({ title: '', content: '' });

  // Settings with school branding
  const [settings, setSettings] = useState({
    office_lat: -6.2000,
    office_lng: 106.8166,
    attendance_radius: 100,
    dept_name: 'PEMERINTAH PROVINSI RIAU',
    sub_dept_name: 'DINAS PENDIDIKAN',
    school_name: 'SMA NEGERI 1 BANTAN',
    school_address: 'Jl. Soekarno Hatta Selatbaru Kode Pos : 28752',
    school_contact: 'Email: sman1.bantan@yahoo.com Website: sman1bantan.sch.id',
    school_accreditation: 'AKREDITASI : A',
    principal_name: 'MARZUL, MPd.',
    principal_nip: '197206121997021001',
    teacher_name: 'Guru Mata Pelajaran',
    teacher_nip: '',
    report_class: 'XI.1',
    logo_left: '',
    logo_right: ''
  });

  useEffect(() => {
    fetchAllData();
  }, []);

  const fetchAllData = async () => {
    setLoading(true);
    try {
      const [u, a, l, c, ann, s] = await Promise.all([
        gasService.getAllUsers(),
        gasService.getAttendance(),
        gasService.getLeaves(),
        gasService.getCorrections(),
        gasService.getAnnouncements(),
        gasService.getSettings()
      ]);
      setUsers(u);
      setAttendance(a);
      setLeaves(l);
      setCorrections(c);
      setAnnouncements(ann);
      if (s && !s.error) {
        setSettings(prev => ({
          ...prev,
          ...s,
          office_lat: parseFloat(s.office_lat) || prev.office_lat,
          office_lng: parseFloat(s.office_lng) || prev.office_lng,
          attendance_radius: parseInt(s.attendance_radius) || prev.attendance_radius
        }));
      }
    } catch (error) {
      console.error("Error fetching admin data:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateStatus = async (type: 'leave' | 'correction', id: string, status: 'approved' | 'rejected') => {
    const success = await gasService.updateRequestStatus(type, id, status);
    if (success) {
      alert("Status berhasil diperbarui");
      fetchAllData();
    }
  };

  const handleAddAnnouncement = async (e: React.FormEvent) => {
    e.preventDefault();
    const success = await gasService.addAnnouncement({ ...newAnn, author: user.name });
    if (success) {
      setNewAnn({ title: '', content: '' });
      alert("Pengumuman dipublikasikan");
      fetchAllData();
    }
  };

  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingSettings(true);
    try {
      const success = await gasService.updateSettings(settings);
      if (success) {
        alert("Konfigurasi instansi berhasil diperbarui!");
      } else {
        alert("Gagal memperbarui pengaturan.");
      }
    } catch (error) {
      alert("Terjadi kesalahan.");
    } finally {
      setIsSavingSettings(false);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>, side: 'logo_left' | 'logo_right') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSettings({ ...settings, [side]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const generateOfficialReport = () => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const today = new Date();
    const monthYear = today.toLocaleDateString('id-ID', { month: 'long', year: 'numeric' });

    // Group attendance by user
    const userAttendanceMap = new Map<string, any>();
    users.filter(u => u.role === 'employee').forEach(u => {
      const userRecords = attendance.filter(a => a.userId === u.id);
      userAttendanceMap.set(u.id, {
        name: u.name,
        records: userRecords,
        counts: {
          S: userRecords.filter(r => r.status === 'sakit').length,
          I: userRecords.filter(r => r.status === 'izin').length,
          A: userRecords.filter(r => r.status === 'alpa').length,
        }
      });
    });

    const rows = Array.from(userAttendanceMap.values()).map((data, index) => `
      <tr>
        <td style="text-align:center">${index + 1}</td>
        <td>${data.name.toUpperCase()}</td>
        ${Array(12).fill('<td></td>').join('')}
        <td style="text-align:center">${data.counts.S || ''}</td>
        <td style="text-align:center">${data.counts.I || ''}</td>
        <td style="text-align:center">${data.counts.A || ''}</td>
        <td></td>
      </tr>
    `).join('');

    const htmlContent = `
      <html>
      <head>
        <title>Rekap Absensi ${settings.school_name}</title>
        <style>
          body { font-family: 'Times New Roman', serif; margin: 0; padding: 20px; font-size: 12px; }
          .header { display: flex; align-items: center; justify-content: center; border-bottom: 3px solid black; padding-bottom: 10px; margin-bottom: 10px; position: relative; }
          .header img { width: 80px; height: 80px; object-fit: contain; }
          .header-text { text-align: center; flex: 1; padding: 0 20px; }
          .header-text h2 { margin: 0; font-size: 16px; }
          .header-text h1 { margin: 0; font-size: 18px; }
          .header-text p { margin: 2px 0; font-size: 11px; }
          .title { text-align: center; font-weight: bold; font-size: 14px; text-decoration: underline; margin: 15px 0; }
          .meta { display: flex; justify-content: space-between; margin-bottom: 10px; }
          .meta-item { display: flex; }
          .meta-item span:first-child { width: 100px; }
          table { width: 100%; border-collapse: collapse; margin-top: 10px; }
          th, td { border: 1px solid black; padding: 4px; font-size: 10px; }
          th { background: #f2f2f2; text-transform: uppercase; }
          .footer { margin-top: 40px; display: flex; justify-content: space-between; padding: 0 50px; }
          .signature-box { text-align: center; min-width: 200px; }
          .signature-space { height: 80px; }
          @media print { .no-print { display: none; } }
        </style>
      </head>
      <body>
        <div class="header">
          ${settings.logo_left ? `<img src="${settings.logo_left}" />` : '<div style="width:80px"></div>'}
          <div class="header-text">
            <h2>${settings.dept_name}</h2>
            <h1>${settings.sub_dept_name}</h1>
            <h1 style="font-size: 20px">${settings.school_name}</h1>
            <p>${settings.school_address}</p>
            <p>${settings.school_contact}</p>
            <p><strong>${settings.school_accreditation}</strong></p>
          </div>
          ${settings.logo_right ? `<img src="${settings.logo_right}" />` : '<div style="width:80px"></div>'}
        </div>

        <div class="title">ABSENSI SISWA</div>

        <div class="meta">
          <div>
            <div class="meta-item"><span>Kelas</span><span>: ${settings.report_class}</span></div>
            <div class="meta-item"><span>Mata Pelajaran</span><span>: ________________</span></div>
          </div>
          <div>
            <div class="meta-item"><span>Bulan</span><span>: ${monthYear}</span></div>
            <div class="meta-item"><span>Tahun Ajaran</span><span>: ${today.getFullYear()}/${today.getFullYear() + 1}</span></div>
          </div>
        </div>

        <table>
          <thead>
            <tr>
              <th rowspan="3">NO</th>
              <th rowspan="2">PERTEMUAN KE</th>
              <th colspan="12">Kehadiran Siswa</th>
              <th colspan="3">Jumlah absensi</th>
              <th rowspan="3">Ket</th>
            </tr>
            <tr>
              ${Array(12).fill('<th></th>').join('')}
              <th rowspan="2">S</th>
              <th rowspan="2">I</th>
              <th rowspan="2">A</th>
            </tr>
            <tr>
              <th>TANGGAL</th>
              <th colspan="12">NAMA SISWA</th>
            </tr>
          </thead>
          <tbody>
            ${rows}
          </tbody>
        </table>

        <div class="footer">
          <div class="signature-box">
            <p>Mengetahui</p>
            <p>Kepala ${settings.school_name}</p>
            <div class="signature-space"></div>
            <p><strong><u>${settings.principal_name}</u></strong></p>
            <p>NIP. ${settings.principal_nip}</p>
          </div>
          <div class="signature-box">
            <p>Selatbaru, ${today.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
            <p>Guru Mata Pelajaran</p>
            <div class="signature-space"></div>
            <p><strong><u>${settings.teacher_name}</u></strong></p>
            <p>NIP. ${settings.teacher_nip || '....'}</p>
          </div>
        </div>

        <div class="no-print" style="margin-top: 50px; text-align: center;">
          <button onclick="window.print()" style="padding: 10px 20px; background: #000; color: #fff; border: none; cursor: pointer; border-radius: 5px;">Print Laporan / Save PDF</button>
        </div>
      </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const todayStr = new Date().toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' }).split('/').join('/');

  return (
    <div className="max-w-6xl mx-auto px-4 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Dashboard Admin</h1>
          <p className="text-sm text-slate-500">Kelola karyawan, absensi, dan identitas instansi.</p>
        </div>
        <button 
          onClick={generateOfficialReport}
          className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-blue-100 flex items-center gap-2 hover:bg-blue-700 transition-all"
        >
          <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
          </svg>
          Print Rekapitulasi Resmi
        </button>
      </div>

      <div className="flex border-b mb-6 overflow-x-auto gap-8 no-scrollbar">
        {[
          { id: 'users', label: 'Data Karyawan/Siswa' },
          { id: 'attendance', label: 'Log Presensi' },
          { id: 'requests', label: 'Permintaan & Izin' },
          { id: 'announcements', label: 'Pengumuman' },
          { id: 'settings', label: 'Pengaturan Instansi' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setTab(item.id as any)}
            className={`pb-4 text-sm font-bold border-b-2 transition-all min-w-fit ${tab === item.id ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
          >
            {item.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <div className="w-10 h-10 border-4 border-slate-200 border-t-blue-600 rounded-full animate-spin"></div>
        </div>
      ) : (
        <div className="animate-in fade-in duration-500">
          {tab === 'users' && (
            <div className="bg-white rounded-[32px] border shadow-sm overflow-hidden">
              <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 border-b">
                  <tr>
                    <th className="px-6 py-4 font-bold text-slate-400 uppercase text-[10px]">Nama & Email</th>
                    <th className="px-6 py-4 font-bold text-slate-400 uppercase text-[10px]">Departemen/Kelas</th>
                    <th className="px-6 py-4 font-bold text-slate-400 uppercase text-[10px]">Role</th>
                    <th className="px-6 py-4 font-bold text-slate-400 uppercase text-[10px]">Face ID</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {users.map(u => (
                    <tr key={u.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-6 py-4">
                        <p className="font-bold text-slate-800">{u.name}</p>
                        <p className="text-xs text-slate-500">{u.email}</p>
                      </td>
                      <td className="px-6 py-4 text-slate-600">{u.department}</td>
                      <td className="px-6 py-4"><span className="px-2 py-1 rounded-full bg-blue-50 text-blue-700 text-[10px] font-bold uppercase">{u.role}</span></td>
