                    <div>
                      <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Longitude</label>
                      <input type="number" step="any" className="w-full p-3 bg-slate-50 border rounded-xl" value={settings.office_lng} onChange={e => setSettings({...settings, office_lng: parseFloat(e.target.value)})} />
