                  <div>
                    <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Dinas Terkait</label>
                    <input type="text" className="w-full p-3 bg-slate-50 border rounded-xl" value={settings.sub_dept_name} onChange={e => setSettings({...settings, sub_dept_name: e.target.value})} />
