                  <div>
                    <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Alamat Lengkap</label>
                    <textarea className="w-full p-3 bg-slate-50 border rounded-xl" rows={2} value={settings.school_address} onChange={e => setSettings({...settings, school_address: e.target.value})} />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Kontak (Email/Web)</label>
                    <input type="text" className="w-full p-3 bg-slate-50 border rounded-xl" value={settings.school_contact} onChange={e => setSettings({...settings, school_contact: e.target.value})} />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Logo Kiri (Dinas)</label>
                      <input type="file" className="text-xs" onChange={e => handleLogoUpload(e, 'logo_left')} />
                      {settings.logo_left && <img src={settings.logo_left} className="h-10 mt-2 border rounded" />}
