                    <div>
                      <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Logo Kanan (Sekolah)</label>
                      <input type="file" className="text-xs" onChange={e => handleLogoUpload(e, 'logo_right')} />
