                  <hr className="my-4" />
                  <h4 className="text-xs font-bold text-slate-800">Penandatangan Laporan</h4>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">Kepala Sekolah</label>
                      <input type="text" className="w-full p-3 bg-slate-50 border rounded-xl" value={settings.principal_name} onChange={e => setSettings({...settings, principal_name: e.target.value})} />
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-slate-400 mb-1 uppercase">NIP Kepala</label>
                      <input type="text" className="w-full p-3 bg-slate-50 border rounded-xl" value={settings.principal_nip} onChange={e => setSettings({...settings, principal_nip: e.target.value})} />
