            {error && (
              <div className="bg-red-50 text-red-600 p-4 rounded-2xl text-xs font-bold border border-red-100 flex items-center gap-3">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                {error}
              </div>
            )}

            <button
              disabled={loading}
              type="submit"
              className="w-full gradient-school text-white p-4 rounded-2xl font-bold text-lg shadow-xl shadow-blue-100 transition-all hover:scale-[1.02] active:scale-[0.98] flex items-center justify-center gap-2"
            >
              {loading ? (
                <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" />
              ) : 'Masuk Sistem'}
            </button>
          </form>

          <div className="pt-10 border-t border-slate-100 text-center space-y-4">
             <p className="text-sm text-slate-500 font-medium">Siswa baru belum punya akses?</p>
             <button 
               onClick={onNavigateToRegister}
               className="w-full py-3 border-2 border-slate-200 rounded-2xl text-slate-700 font-bold hover:bg-slate-50 transition-all flex items-center justify-center gap-2"
             >
               Registrasi Wajah Siswa
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

