              <th colspan="3">Jumlah absensi</th>
              <th rowspan="3">Ket</th>
            </tr>
            <tr>
              ${Array(12).fill('<th></th>').join('')}
              <th rowspan="2">S</th>
              <th rowspan="2">I</th>
              <th rowspan="2">A</th>
            </tr>
            <tr>
              <th>TANGGAL</th>
              <th colspan="12">NAMA SISWA</th>
            </tr>
          </thead>
          <tbody>
            ${rows}
          </tbody>
        </table>
        <div class="footer">
          <div class="signature-box">
            <p>Mengetahui</p>
            <p>Kepala ${settings.school_name}</p>
            <div class="signature-space"></div>
            <p><strong><u>${settings.principal_name}</u></strong></p>
            <p>NIP. ${settings.principal_nip}</p>
          </div>
          <div class="signature-box">
            <p>Selatbaru, ${today.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
