          <button onclick="window.print()" style="padding: 10px 20px; background: #1e3a8a; color: #fff; border: none; cursor: pointer; border-radius: 8px; font-weight: bold;">Cetak Laporan</button>
        </div>
      </body>
      </html>
    `;
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  return (
    <div className="max-w-6xl mx-auto px-4 pb-24 pt-4">
