// --- LOGIKA GOOGLE DRIVE ---

function getOrCreateFolder(parent, folderName) {
  const folders = parent.getFoldersByName(folderName);
  if (folders.hasNext()) return folders.next();
  return parent.createFolder(folderName);
}

/**
 * Fungsi Inti: Menyimpan Base64 ke Drive dengan Folder Rapi
 */
function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  if (!base64Data || !base64Data.includes("base64,")) return base64Data;

  try {
    // 1. Dapatkan Root Folder (EduPresensi_Data)
    let rootFolder = getOrCreateFolder(DriveApp, ROOT_FOLDER_NAME);

    // 2. Dapatkan User Folder (Contoh: "Budi Santoso - U-88271")
    let userFolderName = `${userName} - ${userId}`;
    let userFolder = getOrCreateFolder(rootFolder, userFolderName);

    // 3. Dapatkan Category Folder (Contoh: "Presensi Masuk")
    let categoryFolder = getOrCreateFolder(userFolder, category);

    // 4. Decode Base64
    const splitData = base64Data.split(",");
    const contentType = splitData[0].split(":")[1].split(";")[0];
    const byteData = Utilities.base64Decode(splitData[1]);
    const blob = Utilities.newBlob(byteData, contentType, fileName);

    // 5. Simpan File
    const file = categoryFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // 6. Kembalikan URL Thumbnail (Link ini bisa langsung dibaca oleh tag <img src="...">)
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w1000";
  } catch (e) {
    console.error("Gagal simpan ke Drive:", e);
    return base64Data; // Balikkan base64 jika gagal agar tidak error di aplikasi
  }
}

