  const sheet = SS.getSheetByName("Attendance");
  const id = "ATT-" + Utilities.getUuid().substring(0, 8);
  const dateStr = record.date || Utilities.formatDate(new Date(), "GMT+7", "dd/MM/yyyy");

  const driveUrl = saveToUserDrive(record.selfieIn, record.userName, record.userId, "Presensi Masuk", `Masuk_${dateStr.replace(/\//g,'-')}.jpg`);

  sheet.appendRow([
    id, record.userId.toString(), dateStr, record.clockIn || "", "", 
