// --- DRIVE STORAGE LOGIC ---

function getOrCreateFolder(parent, folderName) {
  const folders = parent.getFoldersByName(folderName);
  if (folders.hasNext()) return folders.next();
  const newFolder = parent.createFolder(folderName);
  newFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
  return newFolder;
}

/**
 * Menyimpan gambar ke Drive dalam folder terstruktur: Root > Nama Siswa > Kategori
 */
function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  if (!base64Data || !base64Data.includes("base64,")) return base64Data;

  try {
    const rootFolder = getOrCreateFolder(DriveApp, ROOT_FOLDER_NAME);
    const userFolder = getOrCreateFolder(rootFolder, `${userName} - ${userId}`);
    const categoryFolder = getOrCreateFolder(userFolder, category);

    const splitData = base64Data.split(",");
    const contentType = splitData[0].split(":")[1].split(";")[0];
    const byteData = Utilities.base64Decode(splitData[1]);
    const blob = Utilities.newBlob(byteData, contentType, fileName);

    const file = categoryFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // Mengembalikan URL Thumbnail publik
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w1000";
  } catch (e) {
    console.error("Gagal simpan Drive: " + e.toString());
    return base64Data;
  }
}

