function registerUser(user) {
  const sheet = SS.getSheetByName("Users");
  const id = "U-" + Math.floor(Math.random() * 1000000).toString();

  // Simpan foto master wajah ke Drive
  const driveUrl = saveToUserDrive(user.faceData, user.name, id, "Foto Rekam Wajah", `Master_${id}.jpg`);

  sheet.appendRow([id, user.email, user.name, "employee", user.department, "123456", driveUrl]);
  return createResponse({ id, ...user, faceData: driveUrl, role: "employee" });
}

function saveAttendance(record) {
  const sheet = SS.getSheetByName("Attendance");
  const id = "ATT-" + Utilities.getUuid().substring(0, 8);
  const now = new Date();
  const dateStr = record.date || Utilities.formatDate(now, "GMT+7", "dd/MM/yyyy");
  const timeLabel = Utilities.formatDate(now, "GMT+7", "HH-mm");

  // Simpan foto selfie masuk ke Drive
  const driveUrl = saveToUserDrive(record.selfieIn, record.userName, record.userId, "Presensi Masuk", `Masuk_${dateStr.replace(/\//g,'-')}_${timeLabel}.jpg`);

  sheet.appendRow([
    id, record.userId.toString(), dateStr, record.clockIn || "", "", 
    record.latin || 0, record.lngin || 0, "", "", 
    record.status || "hadir", driveUrl, "", record.wifiVerified || false, record.userName
  ]);

  return createResponse({ id, ...record, selfieIn: driveUrl });
}

function updateAttendance(update) {
  const sheet = SS.getSheetByName("Attendance");
  const data = sheet.getDataRange().getValues();
  const now = new Date();
  const timeLabel = Utilities.formatDate(now, "GMT+7", "HH-mm");

  for (let i = 1; i < data.length; i++) {
    if (data[i][0].toString() === update.id.toString()) {
      const userName = data[i][13] || "User";
      const userId = data[i][1];

      // Simpan foto selfie keluar ke Drive
      const driveUrl = saveToUserDrive(update.selfieOut, userName, userId, "Presensi Keluar", `Keluar_${timeLabel}.jpg`);

      sheet.getRange(i + 1, 5).setValue(update.clockOut || "");
      sheet.getRange(i + 1, 8).setValue(update.latOut || 0);
      sheet.getRange(i + 1, 9).setValue(update.lngOut || 0);
      sheet.getRange(i + 1, 12).setValue(driveUrl);
      return createResponse({ success: true, id: update.id, selfieOut: driveUrl });
    }
  }
  return createResponse({ success: false });
}

function loginUser(email) {
  const sheet = SS.getSheetByName("Users");
  const data = sheet.getDataRange().getValues();
  const headers = data[0].map(h => h.toString().toLowerCase());
  for (let i = 1; i < data.length; i++) {
    if (data[i][1].toString().toLowerCase() === email.toLowerCase()) {
      let userObj = {};
      headers.forEach((h, idx) => userObj[h] = data[i][idx]);
      return createResponse(userObj);
    }
  }
  return createResponse(null);
}

function getSettings() {
  let sheet = SS.getSheetByName("Settings");
  const data = sheet.getDataRange().getValues();
  let settings = {};
  for (let i = 1; i < data.length; i++) {
    const key = data[i][0];
    const val = data[i][1];
    if (key) settings[key] = val;
  }
  return createResponse(settings);
}

function updateSettings(settings) {
  let sheet = SS.getSheetByName("Settings");
  const data = sheet.getDataRange().getValues();
  for (let key in settings) {
    let found = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] === key) {
        sheet.getRange(i + 1, 2).setValue(settings[key]);
        found = true;
        break;
      }
    }
    if (!found) sheet.appendRow([key, settings[key]]);
  }
  return createResponse({ success: true });
}

function saveToSheet(sheetName, data) {
  const sheet = SS.getSheetByName(sheetName);
  const id = "REQ-" + Utilities.getUuid().substring(0, 8);
  let newRow = [id];
  if (sheetName === "Leaves") {
    newRow.push(data.userId.toString(), data.userName, data.type, data.startDate, data.endDate, data.reason, "pending");
  } else if (sheetName === "Corrections") {
    newRow.push(data.userId.toString(), data.date, data.requestedTime, data.reason, "pending");
  }
  sheet.appendRow(newRow);
  return createResponse({ id, ...data, status: "pending" });
}

function updateRequestStatus(update) {
  const sheetName = update.type === 'leave' ? 'Leaves' : 'Corrections';
  const sheet = SS.getSheetByName(sheetName);
  const data = sheet.getDataRange().getValues();
  const statusCol = sheetName === 'Leaves' ? 8 : 6;
  for (let i = 1; i < data.length; i++) {
    if (data[i][0].toString() === update.id.toString()) {
      sheet.getRange(i + 1, statusCol).setValue(update.status);
      return createResponse({ success: true });
    }
  }
  return createResponse({ success: false });
}

