// --- LOGIKA DRIVE & FOTO ---

function getOrCreateFolder(parent, folderName) {
  const folders = parent.getFoldersByName(folderName);
  if (folders.hasNext()) return folders.next();
  const folder = parent.createFolder(folderName);
  // Set agar bisa dilihat siapa saja (agar foto muncul di web)
  folder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
  return folder;
}

function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  if (!base64Data || !base64Data.includes("base64,")) return base64Data;

  try {
    const rootFolder = getOrCreateFolder(DriveApp, ROOT_FOLDER_NAME);
    const userFolder = getOrCreateFolder(rootFolder, userName + " (" + userId + ")");
    const categoryFolder = getOrCreateFolder(userFolder, category);

    const parts = base64Data.split(",");
    const contentType = parts[0].split(":")[1].split(";")[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);

    const file = categoryFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // Gunakan URL thumbnail agar bisa langsung ditampilkan di <img> tag
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w800";
  } catch (e) {
    Logger.log("Error saving to Drive: " + e.toString());
    return base64Data; // Balik ke base64 jika gagal simpan
  }
}

