// --- LOGIKA PENYIMPANAN GAMBAR ---

function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  if (!base64Data || !base64Data.includes("base64,")) return base64Data;

  try {
    const rootFolder = DriveApp.getFolderById(ROOT_FOLDER_ID);

    // Cari atau buat folder User
    let userFolder;
    const userFolders = rootFolder.getFoldersByName(userName + " (" + userId + ")");
    if (userFolders.hasNext()) {
      userFolder = userFolders.next();
    } else {
      userFolder = rootFolder.createFolder(userName + " (" + userId + ")");
      userFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    }

    // Cari atau buat folder Kategori (Masuk/Keluar/Master)
    let categoryFolder;
    const catFolders = userFolder.getFoldersByName(category);
    if (catFolders.hasNext()) {
      categoryFolder = catFolders.next();
    } else {
      categoryFolder = userFolder.createFolder(category);
      categoryFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    }

    // Simpan File
    const parts = base64Data.split(",");
    const contentType = parts[0].split(":")[1].split(";")[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);

    const file = categoryFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // Link Thumbnail (Paling stabil untuk ditampilkan di aplikasi)
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w1000";
  } catch (e) {
    Logger.log("Gagal simpan Drive: " + e.toString());
    return base64Data; 
  }
}

