/**
 * Fungsi Inti: Mengubah Base64 menjadi Link File Google Drive
 */
function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  // Jika data bukan base64 (sudah berupa link), kembalikan langsung
  if (!base64Data || !base64Data.toString().includes("base64,")) {
    return base64Data;
  }

  try {
    const rootFolder = DriveApp.getFolderById(ROOT_FOLDER_ID);

    // 1. Folder User
    let userFolder;
    const uFolders = rootFolder.getFoldersByName(userName + " (" + userId + ")");
    if (uFolders.hasNext()) {
      userFolder = uFolders.next();
    } else {
      userFolder = rootFolder.createFolder(userName + " (" + userId + ")");
      userFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    }

    // 2. Folder Kategori (Absensi/Master)
    let catFolder;
    const cFolders = userFolder.getFoldersByName(category);
    if (cFolders.hasNext()) {
      catFolder = cFolders.next();
    } else {
      catFolder = userFolder.createFolder(category);
      catFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    }

    // 3. Proses Decode Base64
    const parts = base64Data.split(",");
    const contentType = parts[0].split(":")[1].split(";")[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);

    // 4. Simpan File ke Drive
    const file = catFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    const fileId = file.getId();
    Logger.log("File Berhasil Disimpan: " + fileId);

    // Mengembalikan URL Thumbnail (Agar bisa langsung muncul di aplikasi)
    return "https://drive.google.com/thumbnail?id=" + fileId + "&sz=w1000";
  } catch (e) {
    Logger.log("GAGAL SIMPAN KE DRIVE: " + e.toString());
    // Jika gagal ke drive, tetap kembalikan data asli (base64) agar tidak error, 
    // namun harusnya ini tidak terjadi jika ID Folder benar.
    return base64Data;
  }
}

