/**
 * Fungsi Penyelamat: Mengubah Base64 menjadi Link File Drive
 */
function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  // Jika data kosong atau sudah berupa link, kembalikan apa adanya
  if (!base64Data || !base64Data.toString().includes("base64,")) {
    return base64Data || "";
  }

  try {
    const rootFolder = DriveApp.getFolderById(ROOT_FOLDER_ID);

    // 1. Folder User
    let userFolder;
    const uFolders = rootFolder.getFoldersByName(userName + " (" + userId + ")");
    userFolder = uFolders.hasNext() ? uFolders.next() : rootFolder.createFolder(userName + " (" + userId + ")");
    userFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // 2. Folder Kategori
    let catFolder;
    const cFolders = userFolder.getFoldersByName(category);
    catFolder = cFolders.hasNext() ? cFolders.next() : userFolder.createFolder(category);
    catFolder.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // 3. Decode & Simpan
    const parts = base64Data.split(",");
    const contentType = parts[0].split(":")[1].split(";")[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);

    const file = catFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // RETURN URL (Bukan Base64 lagi!)
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w1000";
  } catch (e) {
    console.error("Drive Error: " + e.toString());
    return "ERROR_DRIVE: " + e.toString();
  }
}

function doGet(e) {
  // Guard untuk manual run
  if (!e || !e.parameter) return ContentService.createTextOutput("Error: Jangan jalankan doGet manual. Deploy sebagai Web App.").setMimeType(ContentService.MimeType.TEXT);

  const action = e.parameter.action;
  try {
    switch (action) {
      case 'login': return createResponse(loginUser(e.parameter.email));
      case 'getAttendance': return createResponse(getDataByUserId("Attendance", e.parameter.userId));
      case 'getLeaves': return createResponse(getDataByUserId("Leaves", e.parameter.userId));
      case 'getCorrections': return createResponse(getDataByUserId("Corrections", e.parameter.userId));
      case 'getAnnouncements': return createResponse(getAllData("Announcements"));
      case 'getAllUsers': return createResponse(getAllData("Users"));
      case 'getSettings': return createResponse(getSettings());
      default: return createResponse({ error: "Invalid action" });
    }
  } catch (err) { return createResponse({ error: err.toString() }); }
}

