        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isFace: { type: Type.BOOLEAN },
            message: { type: Type.STRING }
          },
          required: ['isFace', 'message'],
        }
      }
