const SS = SpreadsheetApp.getActiveSpreadsheet();
const ROOT_FOLDER_ID = 'PASTE_ID_FOLDER_DRIVE_ANDA_DISINI'; 

function getSafeRootFolder() {
  if (!ROOT_FOLDER_ID || ROOT_FOLDER_ID === 'PASTE_ID_FOLDER_DRIVE_ANDA_DISINI' || ROOT_FOLDER_ID.trim() === "") {
    return DriveApp.getRootFolder();
  }
  try {
    return DriveApp.getFolderById(ROOT_FOLDER_ID);
  } catch (e) {
    return DriveApp.getRootFolder();
  }
}

function getParam(e, name) {
  if (!e || !e.parameter) return "";
  if (e.parameter[name]) return e.parameter[name];
  if (e.parameters && e.parameters[name] && e.parameters[name].length > 0) return e.parameters[name][0];
  return "";
}

function doGet(e) {
  const action = getParam(e, "action").toString().trim().toLowerCase();
  const userId = getParam(e, "userId");
  const email = getParam(e, "email");
  const password = getParam(e, "password");
  const fileId = getParam(e, "fileId");

  try {
    switch (action) {
      case 'login': 
        return createResponse(loginUser(email, password));
      case 'getattendance': 
        return createResponse(getDataByUserId("Attendance", userId));
      case 'getleaves': 
        return createResponse(getDataByUserId("Leaves", userId));
      case 'getcorrections': 
        return createResponse(getDataByUserId("Corrections", userId));
      case 'getannouncements': 
        return createResponse(getAllData("Announcements"));
      case 'getallusers': 
        return createResponse(getAllData("Users"));
      case 'getsettings': 
        return createResponse(getSettings());
      case 'getfiledata': 
        return createResponse(getFileData(fileId));
      case 'generatepdf': 
        return createResponse(generateAttendancePDF(userId));
      default: 
        return createResponse({ error: "Invalid GET action: " + action });
    }
  } catch (err) { 
    return createResponse({ error: "System Error: " + err.toString() }); 
  }
}

function doPost(e) {
  const action = getParam(e, "action").toString().trim().toLowerCase();
  let postData;
  try {
    postData = JSON.parse(e.postData.contents);
  } catch(err) {
    return createResponse({ error: "Invalid JSON body" });
  }

  try {
    switch (action) {
      case 'register': 
        return createResponse(registerUser(postData));
      case 'submitattendance': 
        return createResponse(saveAttendance(postData));
      case 'updateattendance': 
        return createResponse(updateAttendance(postData));
      case 'submitleave': 
        return createResponse(saveToSheet("Leaves", postData));
      case 'submitcorrection': 
        return createResponse(saveToSheet("Corrections", postData));
      case 'updaterequeststatus': 
        return createResponse(updateRequestStatus(postData));
      case 'addannouncement': 
        return createResponse(addAnnouncement(postData));
      case 'updatesettings': 
        return createResponse(updateSettings(postData));
      case 'changepassword': 
        return createResponse(changePassword(postData));
      default: 
        return createResponse({ error: "Invalid POST action: " + action });
    }
  } catch (err) { 
    return createResponse({ error: "POST System Error: " + err.toString() }); 
  }
}

function loginUser(email, password) {
  const sheet = SS.getSheetByName("Users");
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return { error: "Database kosong" };

  const headers = data[0].map(h => h.toString().toLowerCase());
  for (let i = 1; i < data.length; i++) {
    // Column 1 (index 1) is Email, Column 6 (index 5) is Password
    if (data[i][1].toString().toLowerCase() === email.toLowerCase()) {
      if (data[i][5].toString() === password.toString()) {
        let obj = {};
        headers.forEach((h, idx) => obj[h] = data[i][idx]);
        return obj;
      } else {
        return { error: "Password salah" };
      }
    }
  }
  return { error: "User tidak ditemukan" };
}

function changePassword(data) {
  const sheet = SS.getSheetByName("Users");
  const values = sheet.getDataRange().getValues();
  for (let i = 1; i < values.length; i++) {
    if (values[i][0].toString() === data.userId.toString()) {
      // Index 5 adalah kolom Password (F)
      if (values[i][5].toString() !== data.currentPassword.toString()) {
        return { error: "Password lama salah." };
      }
      sheet.getRange(i + 1, 6).setValue(data.newPassword);
      return { success: true };
    }
  }
  return { error: "User tidak ditemukan." };
}

function generateAttendancePDF(userId) {
  if (!userId) return { error: "userId required" };
  try {
    const settings = getSettings();
    const attendance = getDataByUserId("Attendance", userId);
    const user = getAllData("Users").find(u => u.id.toString() === userId.toString());
    if (!user) return { error: "User tidak ditemukan" };
    const schoolLogo = settings.logo_right || "";
    const htmlHeader = `
      <div style="text-align:center; border-bottom: 2px solid #333; padding-bottom: 10px; margin-bottom: 20px; font-family: sans-serif;">
        ${schoolLogo ? `<img src="${schoolLogo}" style="height: 60px; float: left;">` : ""}
        <div style="margin-left: 70px;">
          <h2 style="margin:0; text-transform:uppercase; color: #1e3a8a;">${settings.school_name || "LAPORAN KEHADIRAN"}</h2>
          <p style="margin:2px; font-size: 11px;">${settings.school_address || ""}</p>
        </div>
        <div style="clear:both;"></div>
      </div>
    `;
    let rows = "";
    attendance.forEach(rec => {
      rows += `<tr><td style="padding:10px;border-bottom:1px solid #eee;">${rec.date}</td><td style="padding:10px;border-bottom:1px solid #eee;">${rec.clockin}</td><td style="padding:10px;border-bottom:1px solid #eee;">${rec.clockout || "--"}</td><td style="padding:10px;border-bottom:1px solid #eee;">${rec.status}</td></tr>`;
    });
    const fullHtml = `<html><body style="padding:20px;">${htmlHeader}<table style="width:100%;border-collapse:collapse;">${rows}</table></body></html>`;
    const pdfBlob = Utilities.newBlob(fullHtml, 'text/html', 'report.html').getAs('application/pdf');
    return { base64: Utilities.base64Encode(pdfBlob.getBytes()), fileName: `Laporan_${user.name}.pdf` };
  } catch (e) { return { error: e.toString() }; }
}

function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}

function registerUser(user) {
  const sheet = SS.getSheetByName("Users");
  const id = "U-" + Math.floor(Math.random() * 1000000);
  const photoUrl = saveToUserDrive(user.faceData, user.name, id, "Master_Wajah", "Face_Master.jpg");
  sheet.appendRow([id, user.email, user.name, "employee", user.department, "123456", photoUrl]);
  return { id, ...user, facedata: photoUrl, role: "employee" };
}

function saveAttendance(record) {
  const sheet = SS.getSheetByName("Attendance");
  const id = "ATT-" + Utilities.getUuid().substring(0, 8);
  const now = new Date();
  const dateStr = record.date || Utilities.formatDate(now, "GMT+7", "dd/MM/yyyy");
  const photoUrl = saveToUserDrive(record.selfieIn, record.userName, record.userId, "Absensi", "In_" + dateStr.replace(/\//g, "-") + ".jpg");
  sheet.appendRow([id, record.userId, dateStr, record.clockIn, "", record.latIn, record.lngIn, "", "", record.status, photoUrl, "", record.wifiVerified, record.userName]);
  return { id, ...record, selfiein: photoUrl };
}

function updateAttendance(update) {
  const sheet = SS.getSheetByName("Attendance");
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0].toString() === update.id.toString()) {
      const photoUrl = saveToUserDrive(update.selfieOut, data[i][13], data[i][1], "Absensi", "Out_" + data[i][2] + ".jpg");
      sheet.getRange(i + 1, 5).setValue(update.clockOut);
      sheet.getRange(i + 1, 8).setValue(update.latOut);
      sheet.getRange(i + 1, 9).setValue(update.lngOut);
      sheet.getRange(i + 1, 12).setValue(photoUrl);
      return { success: true, selfieout: photoUrl };
    }
  }
  return { success: false };
}

function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  if (!base64Data || !base64Data.toString().includes("base64,")) return base64Data || "";
  try {
    const rootFolder = getSafeRootFolder();
    let userFolder;
    const folderName = userName + " (" + userId + ")";
    const uFolders = rootFolder.getFoldersByName(folderName);
    userFolder = uFolders.hasNext() ? uFolders.next() : rootFolder.createFolder(folderName);
    let catFolder;
    const cFolders = userFolder.getFoldersByName(category);
    catFolder = cFolders.hasNext() ? cFolders.next() : userFolder.createFolder(category);
    const parts = base64Data.split(",");
    const contentType = parts[0].split(":")[1].split(";")[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);
    const file = catFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w1000";
  } catch (e) { return "ERROR_DRIVE: " + e.toString(); }
}

function getAllData(name) {
  const sheet = SS.getSheetByName(name);
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return [];
  const headers = data[0].map(h => h.toString().toLowerCase());
  return data.slice(1).map(row => {
    let o = {};
    headers.forEach((h, idx) => o[h] = row[idx]);
    return o;
  });
}

function getDataByUserId(name, userId) {
  const all = getAllData(name);
  if (!userId) return all;
  return all.filter(item => item.userid && item.userid.toString() === userId.toString());
}

function getSettings() {
  const sheet = SS.getSheetByName("Settings");
  const data = sheet.getDataRange().getValues();
  let set = {};
  for (let i = 1; i < data.length; i++) if (data[i][0]) set[data[i][0]] = data[i][1];
  return set;
}

function updateSettings(settings) {
  const sheet = SS.getSheetByName("Settings");
  for (let key in settings) {
    const data = sheet.getDataRange().getValues();
    let found = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] === key) {
        sheet.getRange(i + 1, 2).setValue(settings[key]);
        found = true; break;
      }
    }
    if (!found) sheet.appendRow([key, settings[key]]);
  }
  return { success: true };
}

function saveToSheet(sheetName, data) {
  const sheet = SS.getSheetByName(sheetName);
  const id = "REQ-" + Utilities.getUuid().substring(0, 8);
  if (sheetName === "Leaves") sheet.appendRow([id, data.userId, data.userName, data.type, data.startDate, data.endDate, data.reason, "pending"]);
  else if (sheetName === "Corrections") sheet.appendRow([id, data.userId, data.date, data.requestedTime, data.reason, "pending"]);
  return { id, status: "pending" };
}

function updateRequestStatus(update) {
  const name = update.type === 'leave' ? 'Leaves' : 'Corrections';
  const sheet = SS.getSheetByName(name);
  const data = sheet.getDataRange().getValues();
  const col = name === 'Leaves' ? 8 : 6;
  for (let i = 1; i < data.length; i++) {
    if (data[i][0].toString() === update.id.toString()) {
      sheet.getRange(i + 1, col).setValue(update.status);
      return { success: true };
    }
  }
  return { success: false };
}

function addAnnouncement(ann) {
  const sheet = SS.getSheetByName("Announcements");
  const date = Utilities.formatDate(new Date(), "GMT+7", "dd/MM/yyyy HH:mm");
  sheet.appendRow([Utilities.getUuid().substring(0, 8), ann.title, ann.content, date, ann.author]);
  return { success: true };
}

function getFileData(fileId) {
  try {
    const file = DriveApp.getFileById(fileId);
    const blob = file.getBlob();
    const base64 = Utilities.base64Encode(blob.getBytes());
    return { base64: base64, mimeType: blob.getContentType() };
  } catch (e) {
    return { error: e.toString() };
  }
}

import { User, AttendanceRecord, LeaveRequest, Announcement, CorrectionRequest, WorkSchedule } from '../types';

/**
 * PENTING: GANTI URL DI BAWAH INI dengan URL Web App (hasil Deploy) milik Anda sendiri!
 */
const GAS_URL = 'https://script.google.com/macros/s/AKfycbxZI0KzUbDG00o23VR0WJm3IY0qZi4Uxo9ihvyPx-SZoptpCIYWSEzooYuPHkm-cxLsrg/exec';

class GasService {
  private async callGas(action: string, method: 'GET' | 'POST', body?: any, params: Record<string, string> = {}) {
    const queryParams = new URLSearchParams({ action: action.toLowerCase(), ...params });
    const url = `${GAS_URL}?${queryParams.toString()}`;

    try {
      const options: RequestInit = {
        method: method,
        mode: 'cors',
      };

      if (method === 'POST' && body) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(url, options);
      if (!response.ok) throw new Error('Network response was not ok');
      const data = await response.json();

      if (data && typeof data === 'object' && data.error) {
        console.error("GAS Business Logic Error:", data.error);
        return data;
      }

      return data;
    } catch (error) {
      console.error(`GAS Service Error (${action}):`, error);
      return { error: String(error) };
    }
  }

  private validateUrl(url: any): string {
    const s = String(url || "");
    if (s.startsWith("ERROR_DRIVE")) return "";
    return s;
  }

  async getFileAsBase64(fileId: string): Promise<string | null> {
    const data = await this.callGas('getFileData', 'GET', null, { fileId });
    if (data && data.base64) return data.base64;
    return null;
  }

  private mapAttendance(a: any): AttendanceRecord {
    return {
      id: a.id?.toString() || '',
      userId: a.userid?.toString() || '',
      userName: a.username || '',
      date: a.date || '',
      clockIn: a.clockin || '',
      clockOut: a.clockout || '',
      latIn: parseFloat(a.latin) || 0,
      lngIn: parseFloat(a.lngin) || 0,
      latOut: parseFloat(a.latout) || 0,
      lngOut: parseFloat(a.lngout) || 0,
      status: a.status || 'hadir',
      selfieIn: this.validateUrl(a.selfiein),
      selfieOut: this.validateUrl(a.selfieout),
      wifiVerified: a.wifiverified === true || a.wifiverified === 'true'
    };
  }

  private mapUser(u: any): User {
    return {
      id: u.id?.toString() || '',
      name: u.name || '',
      email: u.email || '',
      role: u.role || 'employee',
      department: u.department || '',
      faceData: this.validateUrl(u.facedata)
    };
  }

  async login(email: string, password: string): Promise<User | null> {
    const data = await this.callGas('login', 'GET', null, { email, password });
    if (!data || data.error) return null;
    return this.mapUser(data);
  }

  async register(userData: Partial<User>): Promise<User> {
    const data = await this.callGas('register', 'POST', userData);
    if (!data || data.error) throw new Error(data?.error || "Gagal registrasi");
    return this.mapUser(data);
  }

  async submitAttendance(record: Partial<AttendanceRecord>): Promise<AttendanceRecord> {
    const data = await this.callGas('submitAttendance', 'POST', record);
    if (!data || data.error) throw new Error(data?.error || "Gagal absensi");
    return this.mapAttendance(data);
  }

  async updateAttendance(id: string, update: Partial<AttendanceRecord>): Promise<any> {
    const data = await this.callGas('updateAttendance', 'POST', { id, ...update });
    return data;
  }

  async getAttendance(userId?: string): Promise<AttendanceRecord[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getAttendance', 'GET', null, params);
    return Array.isArray(data) ? data.map(a => this.mapAttendance(a)) : [];
  }

  async submitLeave(leave: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const data = await this.callGas('submitLeave', 'POST', leave);
    return data || leave;
  }

  async getLeaves(userId?: string): Promise<LeaveRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getLeaves', 'GET', null, params);
    return Array.isArray(data) ? data.map((l: any) => ({
      ...l,
      id: l.id?.toString(),
      userId: l.userid?.toString(),
      userName: l.username,
      startDate: l.startdate,
      endDate: l.enddate,
      reason: l.reason,
      status: l.status,
      type: l.type
    })) : [];
  }

  async submitCorrection(data: Partial<CorrectionRequest>): Promise<CorrectionRequest> {
    const res = await this.callGas('submitCorrection', 'POST', data);
    return res || data;
  }

  async getCorrections(userId?: string): Promise<CorrectionRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getCorrections', 'GET', null, params);
    return Array.isArray(data) ? data.map((c: any) => ({
      ...c,
      id: c.id?.toString(),
      userId: c.userid?.toString(),
      requestedTime: c.requestedtime,
      date: c.date,
      reason: c.reason,
      status: c.status
    })) : [];
  }

  async getAnnouncements(): Promise<Announcement[]> {
    const data = await this.callGas('getAnnouncements', 'GET');
    return Array.isArray(data) ? data : [];
  }

  async getSchedules(): Promise<WorkSchedule[]> {
    return [
      { day: 'Senin - Jumat', shift: 'Reguler', timeStart: '08:00', timeEnd: '17:00' },
      { day: 'Sabtu', shift: 'Setengah Hari', timeStart: '08:00', timeEnd: '12:00' }
    ];
  }

  async getAllUsers(): Promise<User[]> {
    const data = await this.callGas('getAllUsers', 'GET');
    return Array.isArray(data) ? data.map(u => this.mapUser(u)) : [];
  }

  async updateRequestStatus(type: 'leave' | 'correction', id: string, status: 'approved' | 'rejected'): Promise<boolean> {
    const res = await this.callGas('updateRequestStatus', 'POST', { type, id, status });
    return !!(res && res.success);
  }

  async addAnnouncement(announcement: Partial<Announcement>): Promise<boolean> {
    const res = await this.callGas('addAnnouncement', 'POST', announcement);
    return !!(res && res.success);
  }

  async getSettings(): Promise<any> {
    return await this.callGas('getSettings', 'GET');
  }

  async updateSettings(settings: any): Promise<boolean> {
    const res = await this.callGas('updateSettings', 'POST', settings);
    return !!(res && res.success);
  }

  async downloadAttendancePDF(userId: string): Promise<{base64: string, fileName: string, error?: string} | null> {
    const data = await this.callGas('generatePDF', 'GET', null, { userId });
    if (data && data.base64) return data;
    return data;
  }

  async changePassword(userId: string, currentPassword: string, newPassword: string): Promise<any> {
    return await this.callGas('changePassword', 'POST', { userId, currentPassword, newPassword });
  }
}

