const SS = SpreadsheetApp.getActiveSpreadsheet();
const ROOT_FOLDER_ID = 'PASTE_ID_FOLDER_DRIVE_ANDA_DISINI'; 

function getSafeRootFolder() {
  if (!ROOT_FOLDER_ID || ROOT_FOLDER_ID === 'PASTE_ID_FOLDER_DRIVE_ANDA_DISINI' || ROOT_FOLDER_ID.trim() === "") {
    return DriveApp.getRootFolder();
  }
  try {
    return DriveApp.getFolderById(ROOT_FOLDER_ID);
  } catch (e) {
    return DriveApp.getRootFolder();
  }
}

function getParam(e, name) {
  if (!e || !e.parameter) return "";
  if (e.parameter[name]) return e.parameter[name];
  if (e.parameters && e.parameters[name] && e.parameters[name].length > 0) return e.parameters[name][0];
  return "";
}

function doGet(e) {
  const action = getParam(e, "action").toString().trim().toLowerCase();
  const userId = getParam(e, "userId");
  const email = getParam(e, "email");
  const password = getParam(e, "password");
  const fileId = getParam(e, "fileId");

  try {
    switch (action) {
      case 'login': 
        return createResponse(loginUser(email, password));
      case 'getattendance': 
        return createResponse(getDataByUserId("Attendance", userId));
      case 'getleaves': 
        return createResponse(getDataByUserId("Leaves", userId));
      case 'getcorrections': 
        return createResponse(getDataByUserId("Corrections", userId));
      case 'getannouncements': 
        return createResponse(getAllData("Announcements"));
      case 'getallusers': 
        return createResponse(getAllData("Users"));
      case 'getsettings': 
        return createResponse(getSettings());
      case 'getfiledata': 
        return createResponse(getFileData(fileId));
      case 'generatepdf': 
        return createResponse(generateAttendancePDF(userId));
      case 'generateadminreport':
        const filters = {
          startDate: getParam(e, "startDate"),
          endDate: getParam(e, "endDate"),
          userId: getParam(e, "filterUserId"),
          name: getParam(e, "filterName"),
          status: getParam(e, "filterStatus")
        };
        return createResponse(generateAdminReportPDF(filters));
      default: 
        return createResponse({ error: "Invalid GET action: " + action });
    }
  } catch (err) { 
    return createResponse({ error: "System Error: " + err.toString() }); 
  }
}

function doPost(e) {
  const action = getParam(e, "action").toString().trim().toLowerCase();
  let postData;
  try {
    postData = JSON.parse(e.postData.contents);
  } catch(err) {
    return createResponse({ error: "Invalid JSON body" });
  }

  try {
    switch (action) {
      case 'register': 
        return createResponse(registerUser(postData));
      case 'submitattendance': 
        return createResponse(saveAttendance(postData));
      case 'updateattendance': 
        return createResponse(updateAttendance(postData));
      case 'submitleave': 
        return createResponse(saveToSheet("Leaves", postData));
      case 'submitcorrection': 
        return createResponse(saveToSheet("Corrections", postData));
      case 'updaterequeststatus': 
        return createResponse(updateRequestStatus(postData));
      case 'addannouncement': 
        return createResponse(addAnnouncement(postData));
      case 'updatesettings': 
        return createResponse(updateSettings(postData));
      case 'changepassword': 
        return createResponse(changePassword(postData));
      default: 
        return createResponse({ error: "Invalid POST action: " + action });
    }
  } catch (err) { 
    return createResponse({ error: "POST System Error: " + err.toString() }); 
  }
}

function generateAdminReportPDF(filters) {
  try {
    const settings = getSettings();
    const attendance = getAllData("Attendance");

    // Filtering Logic
    let filtered = attendance.filter(rec => {
      let match = true;
      if (filters.userId && !rec.userid.toString().includes(filters.userId)) match = false;
      if (filters.name && !rec.username.toLowerCase().includes(filters.name.toLowerCase())) match = false;
      if (filters.status && rec.status !== filters.status) match = false;

      if (filters.startDate || filters.endDate) {
        // Assume format dd/mm/yyyy
        const [d, m, y] = rec.date.split('/');
        const recDate = new Date(y, m - 1, d);

        if (filters.startDate) {
          const start = new Date(filters.startDate);
          if (recDate < start) match = false;
        }
        if (filters.endDate) {
          const end = new Date(filters.endDate);
          if (recDate > end) match = false;
        }
      }
      return match;
    });

    const schoolLogo = settings.logo_left || "";
    const htmlHeader = `
      <div style="text-align:center; border-bottom: 2px solid #333; padding-bottom: 10px; margin-bottom: 20px; font-family: sans-serif;">
        <div style="float: left; width: 80px;">
           ${schoolLogo ? `<img src="${schoolLogo}" style="height: 60px;">` : ""}
        </div>
        <div style="margin-left: 90px; margin-right: 90px;">
          <h4 style="margin:0; text-transform:uppercase; font-size: 12px;">${settings.dept_name || ""}</h4>
          <h2 style="margin:0; text-transform:uppercase; color: #1e3a8a; font-size: 18px;">${settings.school_name || "LAPORAN KEHADIRAN"}</h2>
          <p style="margin:2px; font-size: 10px;">${settings.school_address || ""}</p>
        </div>
        <div style="clear:both;"></div>
      </div>
      <h3 style="text-align:center; text-decoration: underline; font-family: sans-serif;">REKAPITULASI KEHADIRAN</h3>
    `;

    let rows = "";
    filtered.forEach((rec, idx) => {
      rows += `
        <tr>
          <td style="padding:8px;border:1px solid #333;text-align:center;">${idx + 1}</td>
          <td style="padding:8px;border:1px solid #333;">${rec.username}<br/><small>${rec.userid}</small></td>
          <td style="padding:8px;border:1px solid #333;text-align:center;">${rec.date}</td>
          <td style="padding:8px;border:1px solid #333;text-align:center;">${rec.clockin}</td>
          <td style="padding:8px;border:1px solid #333;text-align:center;">${rec.clockout || "--"}</td>
          <td style="padding:8px;border:1px solid #333;text-align:center;text-transform:uppercase;">${rec.status}</td>
        </tr>
      `;
    });

    const tableHtml = `
      <table style="width:100%;border-collapse:collapse;font-family:sans-serif;font-size:11px;">
        <thead>
          <tr style="background:#eee;">
            <th style="padding:8px;border:1px solid #333;">NO</th>
            <th style="padding:8px;border:1px solid #333;">NAMA / NISN</th>
            <th style="padding:8px;border:1px solid #333;">TANGGAL</th>
            <th style="padding:8px;border:1px solid #333;">MASUK</th>
            <th style="padding:8px;border:1px solid #333;">PULANG</th>
            <th style="padding:8px;border:1px solid #333;">STATUS</th>
          </tr>
        </thead>
        <tbody>
          ${rows || '<tr><td colspan="6" style="text-align:center;padding:20px;">Data tidak ditemukan</td></tr>'}
        </tbody>
      </table>
    `;

    const footerHtml = `
      <div style="margin-top: 40px; font-family: sans-serif; font-size: 12px; float: right; width: 250px; text-align: center;">
        <p>${settings.report_place_date || "Jakarta, " + Utilities.formatDate(new Date(), "GMT+7", "dd MMMM yyyy")}</p>
        <p style="margin-top: 5px;">Mengetahui,<br/>Kepala Sekolah</p>
        <div style="height: 60px;"></div>
        <p><strong>${settings.principal_name || "...................................."}</strong></p>
        <p style="margin-top: -10px;">NIP. ${settings.principal_nip || "-"}</p>
      </div>
      <div style="clear:both;"></div>
    `;

    const fullHtml = `<html><body style="padding:20px;">${htmlHeader}${tableHtml}${footerHtml}</body></html>`;
    const pdfBlob = Utilities.newBlob(fullHtml, 'text/html', 'report_admin.html').getAs('application/pdf');
    return { 
      base64: Utilities.base64Encode(pdfBlob.getBytes()), 
      fileName: `Rekap_Presensi_${Utilities.formatDate(new Date(), "GMT+7", "yyyyMMdd")}.pdf` 
    };
  } catch (e) {
    return { error: e.toString() };
  }
}

function loginUser(email, password) {
  const sheet = SS.getSheetByName("Users");
  const data = sheet.getDataRange().getValues();
  if (data.length < 2) return { error: "Database kosong" };

  const headers = data[0].map(h => h.toString().toLowerCase());
  for (let i = 1; i < data.length; i++) {
    if (data[i][1].toString().toLowerCase() === email.toLowerCase()) {
      if (data[i][5].toString() === password.toString()) {
        let obj = {};
        headers.forEach((h, idx) => obj[h] = data[i][idx]);
        return obj;
      } else {
        return { error: "Password salah" };
      }
    }
  }
  return { error: "User tidak ditemukan" };
}

function changePassword(data) {
  const sheet = SS.getSheetByName("Users");
  const values = sheet.getDataRange().getValues();
  for (let i = 1; i < values.length; i++) {
    if (values[i][0].toString() === data.userId.toString()) {
      if (values[i][5].toString() !== data.currentPassword.toString()) {
        return { error: "Password lama salah." };
      }
      sheet.getRange(i + 1, 6).setValue(data.newPassword);
      return { success: true };
    }
  }
  return { error: "User tidak ditemukan." };
}

function generateAttendancePDF(userId) {
  if (!userId) return { error: "userId required" };
  try {
    const settings = getSettings();
    const attendance = getDataByUserId("Attendance", userId);
