          <h2 style="margin:0; text-transform:uppercase; color: #1e3a8a;">${settings.school_name || "LAPORAN KEHADIRAN"}</h2>
          <p style="margin:2px; font-size: 11px;">${settings.school_address || ""}</p>
        </div>
        <div style="clear:both;"></div>
      </div>
    `;
    let rows = "";
    attendance.forEach(rec => {
      rows += `<tr><td style="padding:10px;border-bottom:1px solid #eee;">${rec.date}</td><td style="padding:10px;border-bottom:1px solid #eee;">${rec.clockin}</td><td style="padding:10px;border-bottom:1px solid #eee;">${rec.clockout || "--"}</td><td style="padding:10px;border-bottom:1px solid #eee;">${rec.status}</td></tr>`;
    });
    const fullHtml = `<html><body style="padding:20px;">${htmlHeader}<table style="width:100%;border-collapse:collapse;">${rows}</table></body></html>`;
    const pdfBlob = Utilities.newBlob(fullHtml, 'text/html', 'report.html').getAs('application/pdf');
    return { base64: Utilities.base64Encode(pdfBlob.getBytes()), fileName: `Laporan_${user.name}.pdf` };
  } catch (e) { return { error: e.toString() }; }
}

