 */
const GAS_URL = 'https://script.google.com/macros/s/AKfycbzJqPECfBTt-qqF2ahYKHtU5fzKnt-6LkzceH4-6AUDmLL7lL9KajmSGEYJhUPTK56-Eg/exec';

class GasService {
  private async callGas(action: string, method: 'GET' | 'POST', body?: any, params: Record<string, string> = {}) {
    const queryParams = new URLSearchParams({ action: action.toLowerCase(), ...params });
    const url = `${GAS_URL}?${queryParams.toString()}`;

    try {
      const options: RequestInit = {
        method: method,
        mode: 'cors',
      };

      if (method === 'POST' && body) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(url, options);
      if (!response.ok) throw new Error('Network response was not ok');
      const data = await response.json();

      if (data && typeof data === 'object' && data.error) {
        console.error("GAS Business Logic Error:", data.error);
        return data;
      }

      return data;
    } catch (error) {
      console.error(`GAS Service Error (${action}):`, error);
      return { error: String(error) };
    }
  }

  private validateUrl(url: any): string {
    const s = String(url || "");
    if (s.startsWith("ERROR_DRIVE")) return "";
    return s;
  }

  async getFileAsBase64(fileId: string): Promise<string | null> {
    const data = await this.callGas('getFileData', 'GET', null, { fileId });
    if (data && data.base64) return data.base64;
    return null;
  }

  private mapAttendance(a: any): AttendanceRecord {
    return {
      id: a.id?.toString() || '',
      userId: a.userid?.toString() || '',
      userName: a.username || '',
      date: a.date || '',
      clockIn: a.clockin || '',
      clockOut: a.clockout || '',
      latIn: parseFloat(a.latin) || 0,
      lngIn: parseFloat(a.lngin) || 0,
      latOut: parseFloat(a.latout) || 0,
      lngOut: parseFloat(a.lngout) || 0,
      status: a.status || 'hadir',
      selfieIn: this.validateUrl(a.selfiein),
      selfieOut: this.validateUrl(a.selfieout),
      wifiVerified: a.wifiverified === true || a.wifiverified === 'true'
    };
  }

  private mapUser(u: any): User {
    return {
      id: u.id?.toString() || '',
      name: u.name || '',
      email: u.email || '',
      role: u.role || 'employee',
      department: u.department || '',
      faceData: this.validateUrl(u.facedata)
    };
  }

  async login(email: string, password: string): Promise<User | null> {
    const data = await this.callGas('login', 'GET', null, { email, password });
    if (!data || data.error) return null;
    return this.mapUser(data);
  }

  async register(userData: Partial<User>): Promise<User> {
    const data = await this.callGas('register', 'POST', userData);
    if (!data || data.error) throw new Error(data?.error || "Gagal registrasi");
    return this.mapUser(data);
  }

  async submitAttendance(record: Partial<AttendanceRecord>): Promise<AttendanceRecord> {
    const data = await this.callGas('submitAttendance', 'POST', record);
    if (!data || data.error) throw new Error(data?.error || "Gagal absensi");
    return this.mapAttendance(data);
  }

  async updateAttendance(id: string, update: Partial<AttendanceRecord>): Promise<any> {
    const data = await this.callGas('updateAttendance', 'POST', { id, ...update });
    return data;
  }

  async getAttendance(userId?: string): Promise<AttendanceRecord[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getAttendance', 'GET', null, params);
    return Array.isArray(data) ? data.map(a => this.mapAttendance(a)) : [];
  }

  async submitLeave(leave: Partial<LeaveRequest>): Promise<LeaveRequest> {
    const data = await this.callGas('submitLeave', 'POST', leave);
    return data || leave;
  }

  async getLeaves(userId?: string): Promise<LeaveRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getLeaves', 'GET', null, params);
    return Array.isArray(data) ? data.map((l: any) => ({
      ...l,
      id: l.id?.toString(),
      userId: l.userid?.toString(),
      userName: l.username,
      startDate: l.startdate,
      endDate: l.enddate,
      reason: l.reason,
      status: l.status,
      type: l.type
    })) : [];
  }

  async submitCorrection(data: Partial<CorrectionRequest>): Promise<CorrectionRequest> {
    const res = await this.callGas('submitCorrection', 'POST', data);
    return res || data;
  }

  async getCorrections(userId?: string): Promise<CorrectionRequest[]> {
    const params: Record<string, string> = {};
    if (userId) params.userId = userId;
    const data = await this.callGas('getCorrections', 'GET', null, params);
    return Array.isArray(data) ? data.map((c: any) => ({
      ...c,
      id: c.id?.toString(),
      userId: c.userid?.toString(),
      requestedTime: c.requestedtime,
      date: c.date,
      reason: c.reason,
      status: c.status
    })) : [];
  }

  async getAnnouncements(): Promise<Announcement[]> {
    const data = await this.callGas('getAnnouncements', 'GET');
    return Array.isArray(data) ? data : [];
  }

  async getSchedules(): Promise<WorkSchedule[]> {
    return [
      { day: 'Senin - Jumat', shift: 'Reguler', timeStart: '08:00', timeEnd: '17:00' },
      { day: 'Sabtu', shift: 'Setengah Hari', timeStart: '08:00', timeEnd: '12:00' }
    ];
  }

  async getAllUsers(): Promise<User[]> {
    const data = await this.callGas('getAllUsers', 'GET');
    return Array.isArray(data) ? data.map(u => this.mapUser(u)) : [];
  }

  async updateRequestStatus(type: 'leave' | 'correction', id: string, status: 'approved' | 'rejected'): Promise<boolean> {
    const res = await this.callGas('updateRequestStatus', 'POST', { type, id, status });
    return !!(res && res.success);
  }

  async addAnnouncement(announcement: Partial<Announcement>): Promise<boolean> {
    const res = await this.callGas('addAnnouncement', 'POST', announcement);
    return !!(res && res.success);
  }

  async getSettings(): Promise<any> {
    return await this.callGas('getSettings', 'GET');
  }

  async updateSettings(settings: any): Promise<boolean> {
    const res = await this.callGas('updateSettings', 'POST', settings);
    return !!(res && res.success);
  }

  async downloadAttendancePDF(userId: string): Promise<{base64: string, fileName: string, error?: string} | null> {
    const data = await this.callGas('generatePDF', 'GET', null, { userId });
    return data;
  }

  async downloadAdminAttendancePDF(filters: Record<string, string>): Promise<{base64: string, fileName: string, error?: string} | null> {
    const data = await this.callGas('generateadminreport', 'GET', null, filters);
    return data;
  }

  async downloadAdminAttendanceExcel(filters: Record<string, string>): Promise<{base64: string, fileName: string, error?: string} | null> {
    const data = await this.callGas('generateadminexcel', 'GET', null, filters);
    return data;
  }

  async changePassword(userId: string, currentPassword: string, newPassword: string): Promise<any> {
    return await this.callGas('changePassword', 'POST', { userId, currentPassword, newPassword });
  }
}

