    const success = await gasService.updateRequestStatus(type, id, status);
    if (success) {
      alert(`Permintaan berhasil ${status === 'approved' ? 'disetujui' : 'ditolak'}`);
      fetchAllData();
    }
  };

  const handleAddAnnouncement = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmittingAnn(true);
    try {
      const success = await gasService.addAnnouncement({ ...newAnn, author: user.name });
      if (success) {
        setNewAnn({ title: '', content: '' });
        alert("Pengumuman dipublikasikan ke seluruh siswa/pegawai");
        fetchAllData();
      }
    } finally {
      setIsSubmittingAnn(false);
    }
  };

  const handleSaveSettings = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingSettings(true);
    try {
      const success = await gasService.updateSettings(settings);
      if (success) alert("Konfigurasi instansi berhasil diperbarui!");
    } catch (error) {
      alert("Terjadi kesalahan.");
    } finally {
      setIsSavingSettings(false);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>, side: 'logo_left' | 'logo_right') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSettings({ ...settings, [side]: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleExportPDF = async () => {
    setIsExportingPDF(true);
    try {
      const res = await gasService.downloadAdminAttendancePDF(filters);
      if (res && res.base64) {
        const linkSource = `data:application/pdf;base64,${res.base64}`;
        const downloadLink = document.createElement("a");
        downloadLink.href = linkSource;
        downloadLink.download = res.fileName || "Rekap_Kehadiran_Admin.pdf";
        downloadLink.click();
      } else {
        alert("Gagal mengunduh laporan PDF: " + (res?.error || "Unknown error"));
      }
    } catch (err) {
      alert("Kesalahan koneksi.");
    } finally {
      setIsExportingPDF(false);
    }
  };

  const handleExportExcel = async () => {
    setIsExportingExcel(true);
    try {
      const res = await gasService.downloadAdminAttendanceExcel(filters);
      if (res && res.base64) {
        const linkSource = `data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64,${res.base64}`;
        const downloadLink = document.createElement("a");
        downloadLink.href = linkSource;
        downloadLink.download = res.fileName || "Rekap_Kehadiran_Admin.xlsx";
        downloadLink.click();
      } else {
        alert("Gagal mengunduh laporan Excel: " + (res?.error || "Unknown error"));
      }
    } catch (err) {
      alert("Kesalahan koneksi.");
    } finally {
      setIsExportingExcel(false);
    }
  };

  const filteredAttendance = attendance.filter(rec => {
    let match = true;
    if (filters.filterUserId && !rec.userId.toString().includes(filters.filterUserId)) match = false;
    if (filters.filterName && !rec.userName.toLowerCase().includes(filters.filterName.toLowerCase())) match = false;
    if (filters.filterStatus && rec.status !== filters.filterStatus) match = false;

    if (filters.startDate || filters.endDate) {
      const [d, m, y] = rec.date.split('/');
      const recDate = new Date(`${y}-${m}-${d}`);
      if (filters.startDate && recDate < new Date(filters.startDate)) match = false;
      if (filters.endDate && recDate > new Date(filters.endDate)) match = false;
    }
    return match;
  });

  return (
    <div className="max-w-7xl mx-auto px-6 pb-32 pt-6 page-transition">
      {/* Header Admin */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8 mb-12">
        <div className="flex items-center gap-6">
           <div className="w-16 h-16 gradient-brand rounded-3xl flex items-center justify-center text-white shadow-2xl shadow-blue-500/20">
             <svg className="w-9 h-9" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
             </svg>
           </div>
           <div>
             <h1 className="text-4xl font-black text-slate-900 tracking-tighter">Command Center</h1>
             <p className="text-slate-500 font-bold uppercase text-[10px] tracking-[3px] mt-1">Sistem Administrasi Pusat</p>
           </div>
        </div>

        <div className="flex gap-4">
           <div className="bg-white px-8 py-4 rounded-3xl border border-slate-100 flex flex-col justify-center text-center shadow-sm">
              <span className="text-3xl font-black text-blue-600">{users.length}</span>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Total Users</span>
           </div>
           <div className="bg-white px-8 py-4 rounded-3xl border border-slate-100 flex flex-col justify-center text-center shadow-sm">
              <span className="text-3xl font-black text-green-600">{attendance.filter(a => a.date === new Date().toLocaleDateString('id-ID', { day: '2-digit', month: '2-digit', year: 'numeric' }).split('/').join('/')).length}</span>
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Active Today</span>
           </div>
        </div>
      </div>

      {/* Admin Tabs */}
      <div className="flex border-b border-slate-100 mb-10 overflow-x-auto no-scrollbar scroll-smooth gap-10">
        {[
          { id: 'users', label: 'Master Data' },
          { id: 'attendance', label: 'Presence Log' },
          { id: 'requests', label: 'Validations' },
          { id: 'announcements', label: 'Bulletin' },
          { id: 'settings', label: 'Branding' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setTab(item.id as any)}
            className={`pb-5 text-[11px] font-black border-b-4 transition-all min-w-fit uppercase tracking-[3px] ${tab === item.id ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-300 hover:text-slate-500'}`}
          >
            {item.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-40">
           <div className="w-16 h-16 border-8 border-slate-100 border-t-blue-600 rounded-full animate-spin"></div>
        </div>
      ) : (
        <div className="space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-500">

          {/* TAB 1: MASTER DATA */}
          {tab === 'users' && (
            <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-slate-50/50">
                    <tr>
                      <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identitas Digital</th>
                      <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Klasifikasi</th>
                      <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Face ID Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {users.map(u => (
                      <tr key={u.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-10 py-6">
                           <div className="flex items-center gap-4">
                              <div className="w-12 h-12 bg-slate-100 rounded-2xl overflow-hidden border">
                                 <img src={u.faceData || `https://ui-avatars.com/api/?name=${u.name}`} className="w-full h-full object-cover" />
                              </div>
                              <div>
                                 <p className="font-black text-slate-800">{u.name}</p>
                                 <p className="text-xs text-slate-400 font-medium">{u.email}</p>
                              </div>
                           </div>
                        </td>
                        <td className="px-10 py-6">
                           <span className="bg-slate-100 text-slate-600 px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest">{u.department}</span>
                        </td>
                        <td className="px-10 py-6">
                           <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${u.faceData ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-400'}`}>
                              <span className={`w-2 h-2 rounded-full ${u.faceData ? 'bg-green-600' : 'bg-red-400'}`}></span>
                              {u.faceData ? 'Face Registered' : 'Missing Data'}
                           </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
               </table>
            </div>
