                            {isExportingExcel ? 'Exporting...' : 'Export Excel'}
                        </button>
                        <button 
                            onClick={handleExportPDF}
                            disabled={isExportingPDF}
                            className="bg-red-600 text-white px-6 py-3 rounded-2xl text-xs font-black shadow-lg shadow-red-200 hover:bg-red-700 transition-all flex items-center gap-2"
                        >
                            {isExportingPDF ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>}
                            {isExportingPDF ? 'Exporting...' : 'Export PDF'}
                        </button>
                     </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-4">
                     <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Nama Siswa</label>
                        <input 
                          type="text" placeholder="Cari Nama..." 
                          className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold"
                          value={filters.filterName}
                          onChange={e => setFilters({...filters, filterName: e.target.value})}
                        />
                     </div>
                     <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1">NISN / User ID</label>
                        <input 
                          type="text" placeholder="Cari NISN..." 
                          className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold"
                          value={filters.filterUserId}
                          onChange={e => setFilters({...filters, filterUserId: e.target.value})}
                        />
                     </div>
                     <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Status</label>
                        <select 
                          className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold"
                          value={filters.filterStatus}
                          onChange={e => setFilters({...filters, filterStatus: e.target.value})}
                        >
                           <option value="">Semua Status</option>
                           <option value="hadir">Hadir</option>
                           <option value="terlambat">Terlambat</option>
                           <option value="sakit">Sakit</option>
                           <option value="izin">Izin</option>
                           <option value="alpa">Alpa</option>
                        </select>
                     </div>
                     <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Mulai Tanggal</label>
                        <input 
                          type="date" 
                          className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold"
                          value={filters.startDate}
                          onChange={e => setFilters({...filters, startDate: e.target.value})}
                        />
                     </div>
                     <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Sampai Tanggal</label>
                        <input 
                          type="date" 
                          className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold"
                          value={filters.endDate}
                          onChange={e => setFilters({...filters, endDate: e.target.value})}
                        />
                     </div>
                  </div>
               </div>

               <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden">
                  <table className="w-full text-left">
                     <thead className="bg-slate-50/50">
                       <tr>
                         <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">User</th>
                         <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                         <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Time In/Out</th>
                         <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                       </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-100">
                       {filteredAttendance.map(a => (
                         <tr key={a.id} className="hover:bg-slate-50 transition-colors">
                           <td className="px-10 py-6">
                              <p className="font-bold text-slate-800">{a.userName}</p>
                              <p className="text-[10px] text-slate-400 uppercase font-black">{a.userId}</p>
                           </td>
                           <td className="px-10 py-6 text-sm font-medium text-slate-600">{a.date}</td>
                           <td className="px-10 py-6">
                              <div className="flex gap-4">
                                 <div className="flex flex-col">
                                    <span className="text-[8px] font-black text-slate-400 uppercase">In</span>
                                    <span className="text-sm font-bold text-slate-700">{a.clockIn || '--:--'}</span>
                                 </div>
                                 <div className="flex flex-col">
                                    <span className="text-[8px] font-black text-slate-400 uppercase">Out</span>
                                    <span className="text-sm font-bold text-slate-700">{a.clockOut || '--:--'}</span>
                                 </div>
                              </div>
                           </td>
                           <td className="px-10 py-6">
                              <span className={`text-[10px] font-black px-3 py-1.5 rounded-xl uppercase tracking-widest ${
                                a.status === 'hadir' ? 'bg-green-100 text-green-700' : 
                                a.status === 'terlambat' ? 'bg-orange-100 text-orange-700' : 'bg-red-100 text-red-700'
                              }`}>{a.status}</span>
                           </td>
                         </tr>
                       ))}
                       {filteredAttendance.length === 0 && (
                         <tr><td colSpan={4} className="px-10 py-20 text-center text-slate-400 text-sm font-bold uppercase tracking-widest">No Matches Found</td></tr>
                       )}
                     </tbody>
                  </table>
               </div>
            </div>
          )}

          {/* TAB 3: VALIDATIONS (REQUESTS) */}
          {tab === 'requests' && (
            <div className="grid lg:grid-cols-2 gap-10">
               {/* Leaves */}
               <div className="space-y-6">
                  <h3 className="text-lg font-black text-slate-800 uppercase tracking-widest px-2">Leave Requests ({leaves.filter(l => l.status === 'pending').length})</h3>
                  <div className="space-y-4">
                    {leaves.map(l => (
                      <div key={l.id} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm">
                         <div className="flex justify-between items-start mb-4">
                            <div>
                               <p className="font-black text-slate-800">{l.userName}</p>
                               <span className="text-[9px] font-black bg-blue-50 text-blue-600 px-3 py-1 rounded-lg uppercase">{l.type}</span>
                            </div>
                            <span className={`text-[8px] font-black px-2 py-1 rounded-md uppercase ${l.status === 'pending' ? 'bg-slate-100' : l.status === 'approved' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>{l.status}</span>
                         </div>
                         <p className="text-xs text-slate-500 mb-2 font-bold">{l.startDate} s/d {l.endDate}</p>
                         <p className="text-sm text-slate-600 italic bg-slate-50 p-4 rounded-2xl mb-6">"{l.reason}"</p>
                         {l.status === 'pending' && (
                            <div className="flex gap-3">
                               <button onClick={() => handleUpdateStatus('leave', l.id, 'approved')} className="flex-1 bg-green-500 text-white py-2.5 rounded-xl text-xs font-black shadow-lg shadow-green-100 hover:bg-green-600 transition-all">APPROVE</button>
                               <button onClick={() => handleUpdateStatus('leave', l.id, 'rejected')} className="flex-1 bg-white border border-red-200 text-red-500 py-2.5 rounded-xl text-xs font-black hover:bg-red-50 transition-all">REJECT</button>
                            </div>
                         )}
                      </div>
                    ))}
                  </div>
               </div>

               {/* Corrections */}
               <div className="space-y-6">
                  <h3 className="text-lg font-black text-slate-800 uppercase tracking-widest px-2">Correction Requests ({corrections.filter(c => c.status === 'pending').length})</h3>
                  <div className="space-y-4">
                    {corrections.map(c => (
                      <div key={c.id} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm">
                         <div className="flex justify-between items-start mb-4">
                            <div>
                               <p className="font-black text-slate-800">User ID: {c.userId}</p>
                               <span className="text-[9px] font-black bg-orange-50 text-orange-600 px-3 py-1 rounded-lg uppercase">Manual Adj</span>
                            </div>
                            <span className={`text-[8px] font-black px-2 py-1 rounded-md uppercase ${c.status === 'pending' ? 'bg-slate-100' : c.status === 'approved' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>{c.status}</span>
