                               <button onClick={() => handleUpdateStatus('correction', c.id, 'rejected')} className="flex-1 bg-white border border-red-200 text-red-500 py-2.5 rounded-xl text-xs font-black hover:bg-red-50 transition-all">DISCARD</button>
                            </div>
