function generateAdminReportExcel(filters) {
  try {
    const filtered = filterAttendanceData(filters);
    const settings = getSettings();
    const tempSS = SpreadsheetApp.create("Temp_Export_EduPresensi");
    const sheet = tempSS.getSheets()[0];

    const rangeDinas = sheet.getRange("A1:G1");
    rangeDinas.merge().setValue(settings.dept_name || "DINAS PENDIDIKAN");
    rangeDinas.setHorizontalAlignment("center").setFontWeight("bold").setFontSize(10);

    const rangeSekolah = sheet.getRange("A2:G2");
    rangeSekolah.merge().setValue(settings.school_name || "NAMA SEKOLAH");
    rangeSekolah.setHorizontalAlignment("center").setFontWeight("bold").setFontSize(16).setFontColor("#1e3a8a");

    const rangeAlamat = sheet.getRange("A3:G3");
    rangeAlamat.merge().setValue(settings.school_address || "Alamat belum diatur");
    rangeAlamat.setHorizontalAlignment("center").setFontSize(9);

    insertImageToExcel(sheet, settings.logo_left, 1, 1);
    insertImageToExcel(sheet, settings.logo_right, 7, 1);

    sheet.getRange("A4:G4").setBorder(false, false, true, false, false, false, "black", SpreadsheetApp.BorderStyle.DOUBLE);

    const rangeJudul = sheet.getRange("A6:G6");
    rangeJudul.merge().setValue("LAPORAN REKAPITULASI KEHADIRAN");
    rangeJudul.setHorizontalAlignment("center").setFontWeight("bold").setFontSize(12).setFontLine("underline");

    const headerRow = 8;
    const headerLabels = [["NO", "NAMA SISWA", "NISN", "TANGGAL", "JAM MASUK", "JAM PULANG", "STATUS"]];
    const rangeHeader = sheet.getRange(headerRow, 1, 1, 7);
    rangeHeader.setValues(headerLabels).setBackground("#f2f2f2").setFontWeight("bold").setBorder(true, true, true, true, true, true);

    const dataRows = filtered.map((rec, idx) => [
      idx + 1,
      rec.username,
      rec.userid,
      rec.date,
      rec.clockin || "-",
      rec.clockout || "-",
      rec.status.toUpperCase()
    ]);

    if (dataRows.length > 0) {
      const dataRange = sheet.getRange(headerRow + 1, 1, dataRows.length, 7);
      dataRange.setValues(dataRows).setBorder(true, true, true, true, true, true).setHorizontalAlignment("center");
      sheet.getRange(headerRow + 1, 2, dataRows.length, 1).setHorizontalAlignment("left");
    } else {
      const rangeEmpty = sheet.getRange(headerRow + 1, 1, 1, 7);
      rangeEmpty.merge().setValue("TIDAK ADA DATA DITEMUKAN").setHorizontalAlignment("center").setFontStyle("italic");
    }

    const lastDataRow = dataRows.length > 0 ? dataRows.length : 1;
    const footerStartRow = headerRow + lastDataRow + 3;
    const placeDate = settings.report_place_date || "Jakarta, " + Utilities.formatDate(new Date(), "GMT+7", "dd MMMM yyyy");

    sheet.getRange(footerStartRow, 6, 1, 2).merge().setValue(placeDate).setHorizontalAlignment("center");

    sheet.getRange(footerStartRow + 1, 1, 1, 3).merge().setValue("Mengetahui,\nGuru Mata Pelajaran").setHorizontalAlignment("center");
    sheet.getRange(footerStartRow + 5, 1, 1, 3).merge().setValue(settings.teacher_name || "....................................").setHorizontalAlignment("center").setFontWeight("bold");
    sheet.getRange(footerStartRow + 6, 1, 1, 3).merge().setValue("NIP. " + (settings.teacher_nip || "-")).setHorizontalAlignment("center");

    sheet.getRange(footerStartRow + 1, 5, 1, 3).merge().setValue("Mengesahkan,\nKepala Sekolah").setHorizontalAlignment("center");
    sheet.getRange(footerStartRow + 5, 5, 1, 3).merge().setValue(settings.principal_name || "....................................").setHorizontalAlignment("center").setFontWeight("bold");
    sheet.getRange(footerStartRow + 6, 5, 1, 3).merge().setValue("NIP. " + (settings.principal_nip || "-")).setHorizontalAlignment("center");

    sheet.setColumnWidth(1, 40);
    sheet.setColumnWidth(2, 220);
    sheet.setColumnWidth(3, 110);
    sheet.setColumnWidth(4, 90);
    sheet.setColumnWidth(5, 80);
    sheet.setColumnWidth(6, 80);
    sheet.setColumnWidth(7, 90);

    SpreadsheetApp.flush();
    const url = "https://docs.google.com/spreadsheets/d/" + tempSS.getId() + "/export?format=xlsx";
    const params = {
      method: "get",
      headers: { "Authorization": "Bearer " + ScriptApp.getOAuthToken() },
      muteHttpExceptions: true
    };
    const response = UrlFetchApp.fetch(url, params);
    const blob = response.getBlob();
    DriveApp.getFileById(tempSS.getId()).setTrashed(true);

    return {
      base64: Utilities.base64Encode(blob.getBytes()),
      fileName: `Rekap_Presensi_${Utilities.formatDate(new Date(), "GMT+7", "yyyyMMdd")}.xlsx`
    };
  } catch (e) {
    return { error: "Excel Error: " + e.toString() };
  }
}

