  } catch (e) {
    return DriveApp.getRootFolder();
  }
}

function getParam(e, name) {
  if (!e || !e.parameter) return "";
  if (e.parameter[name]) return e.parameter[name];
  if (e.parameters && e.parameters[name] && e.parameters[name].length > 0) return e.parameters[name][0];
  return "";
}

function doGet(e) {
  const action = getParam(e, "action").toString().trim().toLowerCase();
  const userId = getParam(e, "userId");
  const email = getParam(e, "email");
  const password = getParam(e, "password");
  const fileId = getParam(e, "fileId");

  try {
    switch (action) {
      case 'login': 
        return createResponse(loginUser(email, password));
      case 'getattendance': 
        return createResponse(getDataByUserId("Attendance", userId));
      case 'getleaves': 
        return createResponse(getDataByUserId("Leaves", userId));
      case 'getcorrections': 
        return createResponse(getDataByUserId("Corrections", userId));
      case 'getannouncements': 
        return createResponse(getAllData("Announcements"));
      case 'getallusers': 
        return createResponse(getAllData("Users"));
      case 'getsettings': 
        return createResponse(getSettings());
      case 'getfiledata': 
        return createResponse(getFileData(fileId));
      case 'generatepdf': 
        return createResponse(generateAttendancePDF(userId));
      case 'generateadminreport':
        const filters = {
          startDate: getParam(e, "startDate"),
