  const [step, setStep] = useState<'info' | 'face' | 'details'>('info');
  const [formData, setFormData] = useState({
    name: '',
    id: '', // NISN
    username: '',
    email: '',
    department: '', // Kelas
    whatsapp: '',
    password: '',
    subjects: [] as string[],
    faceData: ''
