}

/**
 * Update Pengaturan
 */
function updateSettings(settings) {
  const sheet = SS.getSheetByName("Settings");
  for (let key in settings) {
    const data = sheet.getDataRange().getValues();
    let found = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] === key) {
        sheet.getRange(i + 1, 2).setValue(settings[key]);
        found = true; break;
      }
    }
    if (!found) sheet.appendRow([key, settings[key]]);
  }
  return { success: true };
}

/**
 * Simpan file base64 ke Drive
 */
function saveToUserDrive(base64Data, userName, userId, category, fileName) {
  if (!base64Data || !base64Data.toString().includes("base64,")) return base64Data || "";
  try {
    const rootFolder = getSafeRootFolder();
    let userFolder;
    const folderName = userName + " (" + userId + ")";
    const uFolders = rootFolder.getFoldersByName(folderName);
    userFolder = uFolders.hasNext() ? uFolders.next() : rootFolder.createFolder(folderName);
    let catFolder;
    const cFolders = userFolder.getFoldersByName(category);
    catFolder = cFolders.hasNext() ? cFolders.next() : userFolder.createFolder(category);
    const parts = base64Data.split(",");
    const contentType = parts[0].split(":")[1].split(";")[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);
    const file = catFolder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    return "https://drive.google.com/thumbnail?id=" + file.getId() + "&sz=w1000";
  } catch (e) { return "ERROR_DRIVE: " + e.toString(); }
}

/**
 * Ambil Base64 file dari Drive
 */
function getFileData(fileId) {
  try {
    const file = DriveApp.getFileById(fileId);
    const blob = file.getBlob();
    const base64 = Utilities.base64Encode(blob.getBytes());
    return { base64: base64, mimeType: blob.getContentType() };
  } catch (e) {
    return { error: e.toString() };
  }
}

/**
 * Filter data absensi dengan cerdas (Mapping Nama dari User ID)
 */
function filterAttendanceData(filters) {
  const attendance = getAllData("Attendance");
  const users = getAllData("Users");

  // Buat map User ID -> Name agar Nama Siswa tidak undefined
  const userMap = {};
  users.forEach(u => { 
    if (u.id) userMap[u.id.toString()] = u.name || "Siswa " + u.id; 
  });

  return attendance.filter(rec => {
    // Jika kolom nama di log absensi kosong, lookup dari database user
    if (!rec.username && rec.userid && userMap[rec.userid.toString()]) {
      rec.username = userMap[rec.userid.toString()];
    } else if (!rec.username) {
      rec.username = rec.userid ? "ID: " + rec.userid : "Tanpa Nama";
    }

    let match = true;
    if (filters.userId && !rec.userid.toString().includes(filters.userId)) match = false;
    if (filters.name && !rec.username.toLowerCase().includes(filters.name.toLowerCase())) match = false;
    if (filters.status && rec.status.toLowerCase() !== filters.status.toLowerCase()) match = false;

    if (filters.startDate || filters.endDate) {
      const [d, m, y] = rec.date.split('/');
      const recDate = new Date(y, m - 1, d);
      if (filters.startDate) {
        const start = new Date(filters.startDate);
        start.setHours(0,0,0,0);
        if (recDate < start) match = false;
      }
      if (filters.endDate) {
        const end = new Date(filters.endDate);
        end.setHours(23,59,59,999);
        if (recDate > end) match = false;
      }
    }
    return match;
  });
}

