function updateSettings(settings) {
  const sheet = SS.getSheetByName("Settings");
  for (let key in settings) {
    let val = settings[key];
    // Pastikan jika ada upload logo baru, disimpan ke Drive
    if (key === "logo_left" || key === "logo_right") {
      if (val && val.toString().includes("base64,")) {
        val = saveToUserDrive(val, "Settings", "Branding", "Assets", key + ".jpg");
      }
    }
    const data = sheet.getDataRange().getValues();
    let found = false;
    for (let i = 1; i < data.length; i++) {
      if (data[i][0] === key) { 
        sheet.getRange(i+1, 2).setValue(val); 
        found = true; 
        break; 
      }
    }
    if (!found) sheet.appendRow(safeRow([key, val]));
  }
  return { success: true };
}

function getSettings() {
  const sheet = SS.getSheetByName("Settings");
  if (!sheet) return {};
  const data = sheet.getDataRange().getValues();
  let set = {};
  for (let i = 1; i < data.length; i++) if (data[i][0]) set[data[i][0]] = data[i][1];
  return set;
}

/**
 * Helper untuk mengambil data base64 gambar dari link Drive
 * Digunakan agar PDF generator bisa merender gambar (PDF generator Apps Script tidak bisa ambil link Drive langsung)
 */
function getDriveBase64(url) {
  if (!url || !url.includes("id=")) return "";
  try {
    const id = url.split("id=")[1].split("&")[0];
    const file = DriveApp.getFileById(id);
    const blob = file.getBlob();
    return "data:" + blob.getContentType() + ";base64," + Utilities.base64Encode(blob.getBytes());
  } catch (e) {
    return "";
  }
}

